'use client';

// ColumnBuilder - Premium responsive column builder
// Redesigned for better mobile experience and visual appeal

import { useState } from 'react';
import { Button, Badge } from '@repo/ui';
import { ColumnDefinition } from '../types';
import { COLUMN_TYPES } from '../registry';
import { Trash2 } from 'lucide-react';

interface ColumnBuilderProps {
    columns: ColumnDefinition[];
    onChange: (columns: ColumnDefinition[]) => void;
    availableSources?: { label: string; value: string }[];
}

export const ColumnBuilder = ({ columns, onChange, availableSources = [] }: ColumnBuilderProps) => {
    const addColumn = () => {
        onChange([...columns, { name: '', type: 'string' }]);
    };

    const updateColumn = (index: number, field: keyof ColumnDefinition, value: any) => {
        const updated = [...columns];
        updated[index] = { ...updated[index], [field]: value };
        onChange(updated);
    };

    const removeColumn = (index: number) => {
        onChange(columns.filter((_, i) => i !== index));
    };

    const moveColumn = (index: number, direction: 'up' | 'down') => {
        const newIndex = direction === 'up' ? index - 1 : index + 1;
        if (newIndex < 0 || newIndex >= columns.length) return;

        const updated = [...columns];
        [updated[index], updated[newIndex]] = [updated[newIndex], updated[index]];
        onChange(updated);
    };

    const getTypeInfo = (type: string) => COLUMN_TYPES.find(t => t.value === type);

    const [focusedIndex, setFocusedIndex] = useState<number | null>(null);

    return (
        <div className="space-y-4">
            <div className="flex items-center justify-between px-2">
                <div className="flex items-center gap-3">
                    <div className="w-8 h-8 rounded-lg bg-indigo-50 flex items-center justify-center text-indigo-600 font-bold text-sm">
                        {columns.length}
                    </div>
                    <div>
                        <h3 className="font-bold text-slate-800 text-sm">Defined Columns</h3>
                        <p className="text-xs text-slate-400 hidden sm:block">Configure schema structure</p>
                    </div>
                </div>
                <Button
                    type="button"
                    variant="ghost"
                    onClick={addColumn}
                    className="bg-indigo-50 text-indigo-600 hover:bg-indigo-100 border-transparent transition-colors"
                >
                    <span className="mr-2 text-lg font-bold">+</span> Add Column
                </Button>
            </div>

            {columns.length === 0 ? (
                <div className="text-center py-12 bg-white border-2 border-dashed border-slate-200 rounded-3xl group hover:border-[var(--primary)]/30 hover:bg-[var(--primary)]/5 transition-all cursor-pointer" onClick={addColumn}>
                    <div className="w-16 h-16 rounded-2xl bg-indigo-50 mx-auto flex items-center justify-center text-3xl mb-4 group-hover:scale-110 transition-transform duration-300">
                        Γ£¿
                    </div>
                    <p className="font-bold text-slate-700 text-lg">Start building your schema</p>
                    <p className="text-sm text-slate-400 mt-1 mb-4">Add columns to define your data structure</p>
                    <Button type="button" size="sm" className="bg-white text-[var(--primary)] border border-slate-200 shadow-sm hover:shadow-md">
                        Add First Column
                    </Button>
                </div>
            ) : (
                <div className="space-y-3">
                    {columns.map((col, index) => {
                        const typeInfo = getTypeInfo(col.type);
                        const isFocused = focusedIndex === index;

                        return (
                            <div
                                key={index}
                                className={`
                                    relative bg-white rounded-2xl border transition-all duration-300 group
                                    ${isFocused
                                        ? 'border-[var(--primary)] shadow-lg shadow-indigo-500/10 ring-1 ring-[var(--primary)]/20 z-10 scale-[1.005]'
                                        : 'border-slate-200 hover:border-slate-300 hover:shadow-md'
                                    }
                                `}
                                onFocus={() => setFocusedIndex(index)}
                                onBlur={(e) => {
                                    if (!e.currentTarget.contains(e.relatedTarget)) {
                                        setFocusedIndex(null);
                                    }
                                }}
                            >
                                {/* Drag Handle (Desktop) */}
                                <div className="absolute left-0 top-0 bottom-0 w-1.5 rounded-l-2xl bg-gradient-to-b from-indigo-500/0 via-indigo-500/0 to-indigo-500/0 group-hover:via-indigo-500/20 transition-all"></div>

                                <div className="p-4 sm:p-5">
                                    <div className="flex flex-col md:flex-row gap-5 items-start">

                                        {/* Icon & Controls */}
                                        <div className="flex items-center gap-3 w-full md:w-auto justify-between md:justify-start">
                                            <div className="flex items-center gap-3">
                                                <div className={`
                                                    w-12 h-12 rounded-xl flex items-center justify-center text-xl shadow-sm border
                                                    ${isFocused
                                                        ? 'bg-indigo-600 text-white border-indigo-600 rotate-3'
                                                        : 'bg-white text-slate-600 border-slate-200 group-hover:border-indigo-200 group-hover:text-indigo-600'
                                                    }
                                                    transition-all duration-300
                                                `}>
                                                    {typeInfo?.icon || '≡ƒô¥'}
                                                </div>
                                                <div className="md:hidden">
                                                    <p className="font-bold text-slate-800 text-sm">{col.name || 'Untitled Column'}</p>
                                                    <p className="text-xs text-slate-400">{typeInfo?.label || 'Unknown Type'}</p>
                                                </div>
                                            </div>

                                            {/* Mobile Actions */}
                                            <div className="flex md:hidden items-center gap-1">
                                                <button type="button" onClick={() => moveColumn(index, 'up')} disabled={index === 0} className="p-2 text-slate-400 hover:text-indigo-600">Γû▓</button>
                                                <button type="button" onClick={() => moveColumn(index, 'down')} disabled={index === columns.length - 1} className="p-2 text-slate-400 hover:text-indigo-600">Γû╝</button>
                                                <button type="button" onClick={() => removeColumn(index)} className="p-2 text-red-400 hover:text-red-600">
                                                    <Trash2 className="w-4 h-4" />
                                                </button>
                                            </div>
                                        </div>

                                        {/* Inputs Grid */}
                                        <div className="flex-1 w-full grid grid-cols-1 md:grid-cols-12 gap-4">

                                            {/* Column Name */}
                                            <div className="md:col-span-4 self-center">
                                                <div className="relative">
                                                    <input
                                                        type="text"
                                                        value={col.name}
                                                        onChange={(e) => updateColumn(index, 'name', e.target.value.toLowerCase().replace(/[^a-z0-9_]/g, ''))}
                                                        placeholder="column_name"
                                                        className="w-full pl-3 pr-3 py-2.5 rounded-xl border border-slate-200 bg-slate-50/50 font-mono text-sm font-medium focus:bg-white focus:ring-4 focus:ring-indigo-500/10 focus:border-indigo-500 outline-none transition-all placeholder:text-slate-400"
                                                    />
                                                    <div className="absolute right-3 top-1/2 -translate-y-1/2 pointer-events-none text-xs text-slate-400">
                                                        SQL
                                                    </div>
                                                </div>
                                            </div>

                                            {/* Type Selector */}
                                            <div className="md:col-span-4 self-center">
                                                <div className="relative">
                                                    <select
                                                        value={col.type}
                                                        onChange={(e) => updateColumn(index, 'type', e.target.value)}
                                                        className="w-full px-3 py-2.5 rounded-xl border border-slate-200 bg-white text-sm font-medium focus:ring-4 focus:ring-indigo-500/10 focus:border-indigo-500 outline-none appearance-none cursor-pointer hover:border-slate-300 transition-all pl-10"
                                                    >
                                                        {COLUMN_TYPES.map(t => (
                                                            <option key={t.value} value={t.value}>
                                                                {t.label}
                                                            </option>
                                                        ))}
                                                    </select>
                                                    <div className="absolute left-3 top-1/2 -translate-y-1/2 pointer-events-none text-lg">
                                                        {typeInfo?.icon}
                                                    </div>
                                                    <div className="absolute right-3 top-1/2 -translate-y-1/2 pointer-events-none text-slate-400 text-xs">
                                                        Γû╝
                                                    </div>
                                                </div>
                                            </div>

                                            {/* Toggles */}
                                            <div className="md:col-span-4 flex items-center justify-start md:justify-end gap-3 self-center">
                                                <label className={`
                                                    flex items-center gap-2 px-3 py-2 rounded-xl border transition-all cursor-pointer text-xs font-bold uppercase tracking-wider select-none
                                                    ${col.required
                                                        ? 'bg-amber-50 border-amber-200 text-amber-700'
                                                        : 'bg-white border-slate-200 text-slate-400 hover:border-slate-300'
                                                    }
                                                `}>
                                                    <input
                                                        type="checkbox"
                                                        checked={col.required || false}
                                                        onChange={(e) => updateColumn(index, 'required', e.target.checked)}
                                                        className="hidden"
                                                    />
                                                    <span>Required</span>
                                                </label>

                                                <label className={`
                                                    flex items-center gap-2 px-3 py-2 rounded-xl border transition-all cursor-pointer text-xs font-bold uppercase tracking-wider select-none
                                                    ${col.unique
                                                        ? 'bg-purple-50 border-purple-200 text-purple-700'
                                                        : 'bg-white border-slate-200 text-slate-400 hover:border-slate-300'
                                                    }
                                                `}>
                                                    <input
                                                        type="checkbox"
                                                        checked={col.unique || false}
                                                        onChange={(e) => updateColumn(index, 'unique', e.target.checked)}
                                                        className="hidden"
                                                    />
                                                    <span>Unique</span>
                                                </label>
                                            </div>
                                        </div>

                                        {/* Desktop Actions */}
                                        <div className="hidden md:flex items-center gap-1 opacity-0 group-hover:opacity-100 transition-opacity self-center">
                                            <div className="flex flex-col">
                                                <button type="button" onClick={() => moveColumn(index, 'up')} disabled={index === 0} className="w-8 h-8 flex items-center justify-center text-slate-400 hover:text-indigo-600 rounded-lg hover:bg-slate-50 disabled:opacity-30">Γû▓</button>
                                                <button type="button" onClick={() => moveColumn(index, 'down')} disabled={index === columns.length - 1} className="w-8 h-8 flex items-center justify-center text-slate-400 hover:text-indigo-600 rounded-lg hover:bg-slate-50 disabled:opacity-30">Γû╝</button>
                                            </div>
                                            <div className="w-px h-8 bg-slate-100 mx-1"></div>
                                            <button
                                                type="button"
                                                onClick={() => removeColumn(index)}
                                                className="w-9 h-9 flex items-center justify-center text-slate-400 hover:text-red-600 hover:bg-red-50 rounded-xl transition-colors"
                                            >
                                                <Trash2 className="w-4 h-4" />
                                            </button>
                                        </div>
                                    </div>

                                    {/* Expanded Configuration Area */}
                                    {(typeInfo?.requiresValues || typeInfo?.requiresTarget || col.type === 'string' || col.type === 'slug') && (
                                        <div className="mt-4 pt-4 border-t border-slate-100 pl-0 md:pl-[4.25rem]">
                                            <div className="flex flex-wrap items-center gap-4 animate-in fade-in slide-in-from-top-1">
                                                {/* Arrow Pointer */}
                                                <div className="hidden md:block absolute left-[3.5rem] top-[5.5rem] w-4 h-4 border-l border-b border-slate-200 -rotate-45 bg-white"></div>

                                                {/* Enum Values */}
                                                {typeInfo?.requiresValues && (
                                                    <div className="flex-1 min-w-[200px]">
                                                        <label className="text-[10px] font-bold text-slate-400 uppercase tracking-widest mb-1.5 block">Allowed Values (Comma Separated)</label>
                                                        <input
                                                            type="text"
                                                            value={(col.values || []).join(', ')}
                                                            onChange={(e) => updateColumn(index, 'values', e.target.value.split(',').map(v => v.trim()).filter(Boolean))}
                                                            placeholder="pending, active, suspended"
                                                            className="w-full px-3 py-2 rounded-lg border border-slate-200 text-sm focus:ring-2 focus:ring-indigo-500/20 focus:border-indigo-500 outline-none"
                                                        />
                                                    </div>
                                                )}

                                                {/* Relation Target */}
                                                {typeInfo?.requiresTarget && (
                                                    <div className="flex-1 min-w-[200px]">
                                                        <label className="text-[10px] font-bold text-slate-400 uppercase tracking-widest mb-1.5 block">Target Table</label>
                                                        <select
                                                            value={col.target || ''}
                                                            onChange={(e) => updateColumn(index, 'target', e.target.value)}
                                                            className="w-full px-3 py-2 rounded-lg border border-slate-200 text-sm focus:ring-2 focus:ring-indigo-500/20 focus:border-indigo-500 outline-none"
                                                        >
                                                            <option value="" disabled>Select a table...</option>
                                                            {availableSources.map(s => (
                                                                <option key={s.value} value={s.value}>{s.label}</option>
                                                            ))}
                                                        </select>
                                                    </div>
                                                )}

                                                {/* String Length */}
                                                {col.type === 'string' && (
                                                    <div className="w-[120px]">
                                                        <label className="text-[10px] font-bold text-slate-400 uppercase tracking-widest mb-1.5 block">Max Length</label>
                                                        <input
                                                            type="number"
                                                            value={col.length || 255}
                                                            onChange={(e) => updateColumn(index, 'length', parseInt(e.target.value) || 255)}
                                                            className="w-full px-3 py-2 rounded-lg border border-slate-200 text-sm focus:ring-2 focus:ring-indigo-500/20 focus:border-indigo-500 outline-none"
                                                        />
                                                    </div>
                                                )}

                                                {/* Generic Hints */}
                                                <div className="text-xs text-slate-400 italic">
                                                    {col.type === 'slug' && 'Will be auto-generated from "title" or "name" column if available.'}
                                                    {col.type === 'string' && 'Standard text field up to 65k chars, but recommend keeping it short.'}
                                                    {col.type === 'relation' && 'Creates a foreign key to another table.'}
                                                </div>
                                            </div>
                                        </div>
                                    )}
                                </div>
                            </div>
                        );
                    })}
                </div>
            )}
        </div>
    );
};

'use client';

// CreateSourceForm - Full page form for creating data sources
// Pure UI component - all data operations via useCreateSource composable

import { useState, useEffect } from 'react';
import { useRouter } from 'next/navigation';
import { Button, Badge } from '@repo/ui';
import { Icons } from '@/modules/_core';
import { ColumnBuilder } from './ColumnBuilder';
import { useCreateSource } from '../composables';
import { DEFAULTS } from '../config';
import type { ColumnDefinition } from '../types';

export const CreateSourceForm = () => {
    const router = useRouter();

    // All data operations from composable
    const {
        submitting,
        validating,
        validationResult,
        templates,
        loadingTemplates,
        availableSources,
        validate,
        create,
        generateTableName,
        defaultOptions,
    } = useCreateSource();

    // Form state (UI only)
    const [form, setForm] = useState({
        name: '',
        tableName: '',
        description: '',
    });

    const [columns, setColumns] = useState<ColumnDefinition[]>([
        { name: 'title', type: 'string', required: true },
        { name: 'slug', type: 'slug', unique: true, target: 'title' },
        { name: 'status', type: 'status', values: ['draft', 'published', 'archived'] }
    ]);

    const [options, setOptions] = useState({
        timestamps: defaultOptions.timestamps,
        softDelete: defaultOptions.softDelete,
    });

    // Debounced validation when form changes
    useEffect(() => {
        if (!form.tableName) return;

        const timer = setTimeout(() => {
            validate(form.tableName, columns, options);
        }, DEFAULTS.debounce_ms);

        return () => clearTimeout(timer);
    }, [form.tableName, columns, options, validate]);

    // Auto-generate table name from display name
    const handleNameChange = (val: string) => {
        const newForm = { ...form, name: val };
        if (!form.tableName && val) {
            newForm.tableName = generateTableName(val);
        }
        setForm(newForm);
    };

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();

        const result = await create({
            name: form.name,
            tableName: form.tableName,
            description: form.description,
            schema: {
                columns,
                timestamps: options.timestamps,
                softDelete: options.softDelete,
            },
        });

        if (result) {
            router.push('/data-sources');
        }
    };

    const applyTemplate = (tpl: any) => {
        setForm({
            name: form.name || tpl.name,
            tableName: form.tableName || '',
            description: tpl.description,
        });
        setColumns(tpl.schema.columns);
        setOptions(prev => ({
            ...prev,
            timestamps: tpl.schema.timestamps ?? true,
        }));
        window.scrollTo({ top: 300, behavior: 'smooth' });
    };

    return (
        <div className="space-y-8 animate-in fade-in slide-in-from-bottom-4 duration-500">
            {/* Section 0: Template Gallery */}
            <div className="bg-gradient-to-br from-indigo-900 to-violet-900 rounded-[2rem] p-8 text-white shadow-xl shadow-indigo-900/20">
                <div className="flex items-center gap-4 mb-6">
                    <div className="w-12 h-12 rounded-2xl bg-white/10 backdrop-blur-md flex items-center justify-center"><Icons.sparkles className="w-6 h-6" /></div>
                    <div>
                        <h2 className="text-2xl font-bold">Start from a Template</h2>
                        <p className="text-indigo-200">Choose a pre-built schema to get started instantly.</p>
                    </div>
                </div>

                {loadingTemplates ? (
                    <div className="flex gap-4 overflow-x-auto pb-4">
                        {[1, 2, 3].map(i => <div key={i} className="w-64 h-40 bg-white/5 rounded-2xl animate-pulse flex-shrink-0"></div>)}
                    </div>
                ) : (
                    <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-4">
                        {templates.map(tpl => (
                            <button
                                key={tpl.id}
                                type="button"
                                onClick={() => applyTemplate(tpl)}
                                className="bg-white/10 hover:bg-white/20 hover:scale-[1.02] transition-all p-4 rounded-xl text-left border border-white/5 flex flex-col h-full group"
                            >
                                <span className="text-3xl mb-3 block group-hover:scale-110 transition-transform origin-left">{tpl.icon}</span>
                                <h3 className="font-bold text-lg mb-1">{tpl.name}</h3>
                                <p className="text-xs text-indigo-200 leading-relaxed mb-4 flex-1">{tpl.description}</p>
                                <div className="mt-auto flex items-center gap-2 text-xs font-bold bg-white/10 w-fit px-2 py-1 rounded-lg">
                                    <span>Use Template</span>
                                    <span>ΓåÆ</span>
                                </div>
                            </button>
                        ))}
                    </div>
                )}
            </div>

            <form onSubmit={handleSubmit} className="space-y-8">
                {/* Section 1: Basic Info */}
                <div className="bg-white rounded-[2rem] border border-slate-100 p-8 shadow-sm">
                    <div className="flex items-center gap-3 mb-6">
                        <div className="w-10 h-10 rounded-xl bg-indigo-50 flex items-center justify-center text-indigo-600"><Icons.info className="w-5 h-5" /></div>
                        <h2 className="text-xl font-bold text-slate-800">Basic Information</h2>
                    </div>

                    <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
                        <div>
                            <label className="block text-sm font-bold text-slate-700 mb-2">
                                Display Name <span className="text-red-500">*</span>
                            </label>
                            <input
                                type="text"
                                value={form.name}
                                onChange={(e) => handleNameChange(e.target.value)}
                                placeholder="e.g. Product Catalog"
                                className="w-full px-4 py-3.5 rounded-xl border border-slate-200 focus:ring-4 focus:ring-[var(--primary)]/10 focus:border-[var(--primary)] outline-none transition-all font-medium"
                                required
                            />
                            <p className="text-xs text-slate-400 mt-2">Human-readable name for the dashboard.</p>
                        </div>

                        <div>
                            <label className="block text-sm font-bold text-slate-700 mb-2">
                                Table Name (SQL) <span className="text-red-500">*</span>
                            </label>
                            <div className="relative">
                                <input
                                    type="text"
                                    value={form.tableName}
                                    onChange={(e) => setForm({ ...form, tableName: e.target.value.toLowerCase().replace(/[^a-z0-9_]/g, '') })}
                                    placeholder="e.g. product_catalog"
                                    className={`w-full px-4 py-3.5 rounded-xl border outline-none transition-all font-mono text-sm ${validationResult?.errors?.some(e => e.includes('Table') || e.includes('reserved prefix'))
                                        ? 'border-red-300 focus:ring-4 focus:ring-red-100'
                                        : validationResult && !validating
                                            ? 'border-green-300 focus:ring-4 focus:ring-green-100'
                                            : 'border-slate-200 focus:ring-4 focus:ring-[var(--primary)]/10 focus:border-[var(--primary)]'
                                        }`}
                                    required
                                />
                                {validating && (
                                    <div className="absolute right-4 top-1/2 -translate-y-1/2">
                                        <div className="w-4 h-4 border-2 border-slate-300 border-t-transparent animate-spin rounded-full"></div>
                                    </div>
                                )}
                                {!validating && validationResult && !validationResult.errors?.some(e => e.includes('Table') || e.includes('reserved prefix')) && (
                                    <div className="absolute right-4 top-1/2 -translate-y-1/2 text-green-500 text-lg">Γ£ô</div>
                                )}
                            </div>
                            {validationResult?.sanitizedTableName && (
                                <div className="mt-2 flex items-center gap-2">
                                    <Badge variant="slate">usr_{validationResult.sanitizedTableName}</Badge>
                                    <span className="text-xs text-slate-400">Final database table name</span>
                                </div>
                            )}
                            {validationResult?.errors && validationResult.errors.filter(e => e.includes('Table') || e.includes('reserved prefix')).length > 0 && (
                                <p className="text-sm text-red-500 mt-2 font-medium">
                                    {validationResult.errors.filter(e => e.includes('Table') || e.includes('reserved prefix'))[0]}
                                </p>
                            )}
                        </div>

                        <div className="md:col-span-2">
                            <label className="block text-sm font-bold text-slate-700 mb-2">Description</label>
                            <input
                                type="text"
                                value={form.description}
                                onChange={(e) => setForm({ ...form, description: e.target.value })}
                                placeholder="Optional: What is this data source used for?"
                                className="w-full px-4 py-3.5 rounded-xl border border-slate-200 focus:ring-4 focus:ring-[var(--primary)]/10 focus:border-[var(--primary)] outline-none transition-all"
                            />
                        </div>
                    </div>
                </div>

                {/* Section 2: Schema */}
                <div className="bg-white rounded-[2rem] border border-slate-100 p-8 shadow-sm">
                    <div className="flex items-center gap-3 mb-6">
                        <div className="w-10 h-10 rounded-xl bg-indigo-50 flex items-center justify-center text-indigo-600"><Icons.clipboardList className="w-5 h-5" /></div>
                        <div>
                            <h2 className="text-xl font-bold text-slate-800">Schema Definition</h2>
                            <p className="text-sm text-slate-500">Define the columns and data types for your table.</p>
                        </div>
                    </div>

                    <div className="-mx-4 sm:mx-0">
                        <ColumnBuilder
                            columns={columns}
                            onChange={setColumns}
                            availableSources={availableSources}
                        />
                        {validationResult?.errors && validationResult.errors.filter(e => !e.includes('Table') && !e.includes('reserved prefix')).length > 0 && (
                            <div className="mt-4 p-4 bg-red-50 text-red-600 rounded-xl border border-red-100 text-sm flex items-start gap-3">
                                <Icons.warning className="w-5 h-5 flex-shrink-0 mt-0.5" />
                                <div>
                                    <p className="font-bold">Schema Validation Errors</p>
                                    <ul className="list-disc pl-4 mt-1 space-y-1">
                                        {validationResult.errors.filter(e => !e.includes('Table') && !e.includes('reserved prefix')).map((err, i) => (
                                            <li key={i}>{err}</li>
                                        ))}
                                    </ul>
                                </div>
                            </div>
                        )}
                    </div>
                </div>

                {/* Section 3: Options */}
                <div className="bg-white rounded-[2rem] border border-slate-100 p-8 shadow-sm">
                    <div className="flex items-center gap-3 mb-6">
                        <div className="w-10 h-10 rounded-xl bg-indigo-50 flex items-center justify-center text-indigo-600"><Icons.settings className="w-5 h-5" /></div>
