                                className="mt-1 w-5 h-5 rounded border-slate-300 text-[var(--primary)] focus:ring-[var(--primary)]"
                            />
                            <div>
                                <span className="block font-bold text-slate-800 mb-1">Soft Delete</span>
                                <p className="text-sm text-slate-500">Don&apos;t permanently delete rows. Instead, set a <code className="text-xs bg-white px-1 py-0.5 rounded border border-slate-200">deleted_at</code> timestamp.</p>
                            </div>
                        </label>
                    </div>
                </div>

                {/* Actions */}
                <div className="sticky bottom-4 bg-white/80 backdrop-blur-md p-4 rounded-2xl border border-slate-200 shadow-xl flex items-center justify-between">
                    <Button
                        type="button"
                        variant="ghost"
                        onClick={() => router.back()}
                        className="text-slate-500 hover:text-slate-700"
                    >
                        Cancel
                    </Button>
                    <div className="flex items-center gap-4">
                        {validationResult?.valid === false && (
                            <span className="text-sm text-red-500 font-medium animate-pulse">
                                Please fix validation errors
                            </span>
                        )}
                        <Button
                            type="submit"
                            size="lg"
                            isLoading={submitting}
                            disabled={validationResult?.valid === false || submitting}
                            className="min-w-[200px]"
                        >
                            Create Data Source
                        </Button>
                    </div>
                </div>

                <div className="h-12"></div>
            </form>
        </div>
    );
};

'use client';

// DataSourcesView - Enhanced with Premium Mobile-First UI
// Uses composables for all data operations, component is pure UI
// MIGRATED: All strings now from @repo/config

import { useState, useMemo } from 'react';
import { useRouter } from 'next/navigation';
import { Button, Badge } from '@repo/ui';
import { MODULE_LABELS, COMMON_LABELS } from '@repo/config';
import { ConfirmDialog, Icons } from '@/modules/_core';
import { useDataSources, useDataSourceActions, useResources } from '../composables';
import type { DataSource } from '../types';

// Shorthand for labels
const L = MODULE_LABELS.dataSources;
const C = COMMON_LABELS;

export const DataSourcesView = () => {
    const router = useRouter();

    // Data from composables (no fetch logic here)
    const { items: sources, loading, remove, fetchAll } = useDataSources();
    const { clone } = useDataSourceActions();

    // Resource Expansion State
    const [expandedId, setExpandedId] = useState<number | null>(null);
    const { items: resources, loading: loadingResources, remove: removeResource } = useResources(expandedId);

    // Confirm dialog state
    const [confirmDialog, setConfirmDialog] = useState<{
        id: number;
        name: string;
        type?: 'source' | 'resource';
        sourceId?: number;
    } | null>(null);
    const [submitting, setSubmitting] = useState(false);

    // Calculate stats from sources (derived, no API call)
    const stats = useMemo(() => {
        const totalRecords = sources.reduce((acc, src) => acc + (src.rowCount || 0), 0);
        return {
            total_sources: sources.length,
            total_tables: sources.length,
            total_records: totalRecords,
        };
    }, [sources]);

    // UI handlers (delegate to composables)
    const toggleExpand = (id: number) => {
        if (expandedId === id) {
            setExpandedId(null);
        } else {
            setExpandedId(id);
        }
    };

    const handleDelete = async () => {
        if (!confirmDialog) return;
        setSubmitting(true);

        if (confirmDialog.type === 'resource') {
            await removeResource(confirmDialog.id);
        } else {
            await remove(confirmDialog.id);
        }

        setSubmitting(false);
        setConfirmDialog(null);
    };

    const handleClone = async (id: number) => {
        const result = await clone(id);
        if (result) {
            fetchAll();
        }
    };

    // Loading state
    if (loading) {
        return (
            <div className="p-12 text-center text-slate-400 animate-pulse">
                {L.labels.loadingDataSources}
            </div>
        );
    }

    return (
        <div className="space-y-8 animate-page-enter">
            {/* Header & Stats */}
            <div className="grid grid-cols-1 md:grid-cols-4 gap-6">
                <div className="md:col-span-1">
                    <h1 className="text-3xl font-bold text-slate-900 mb-2 tracking-tight">{L.title}</h1>
                    <p className="text-slate-500 text-sm leading-relaxed">
                        {L.subtitle}
                    </p>
                    <div className="mt-6">
                        <Button
                            className="w-full justify-center shadow-lg shadow-indigo-500/20 py-6 text-lg hover:scale-[1.02] transition-transform"
                            onClick={() => router.push('/data-sources/create')}
                        >
                            {L.buttons.newDataSource}
                        </Button>
                    </div>
                </div>

                {/* Stat Cards */}
                <div className="bg-gradient-to-br from-violet-500 to-indigo-600 rounded-[2rem] p-6 text-white shadow-xl shadow-indigo-200">
                    <div className="flex items-start justify-between">
                        <div className="p-3 bg-white/20 rounded-2xl backdrop-blur-sm"><Icons.bookOpen className="w-6 h-6" /></div>
                        <span className="text-indigo-100 text-xs font-bold uppercase tracking-wider backdrop-blur-sm bg-white/10 px-2 py-1 rounded-lg">{L.labels.sources}</span>
                    </div>
                    <div className="mt-6">
                        <div className="text-4xl font-bold tracking-tighter">{stats.total_sources}</div>
                        <p className="text-indigo-100/80 text-sm mt-1">{L.labels.activeConnections}</p>
                    </div>
                </div>

                <div className="bg-gradient-to-br from-emerald-400 to-teal-600 rounded-[2rem] p-6 text-white shadow-xl shadow-teal-200">
                    <div className="flex items-start justify-between">
                        <div className="p-3 bg-white/20 rounded-2xl backdrop-blur-sm"><Icons.storage className="w-6 h-6" /></div>
                        <span className="text-teal-50 text-xs font-bold uppercase tracking-wider backdrop-blur-sm bg-white/10 px-2 py-1 rounded-lg">{L.labels.tables}</span>
                    </div>
                    <div className="mt-6">
                        <div className="text-4xl font-bold tracking-tighter">{stats.total_tables}</div>
                        <p className="text-teal-100/80 text-sm mt-1">{L.labels.schemasDefined}</p>
                    </div>
                </div>

                <div className="bg-gradient-to-br from-amber-400 to-orange-500 rounded-[2rem] p-6 text-white shadow-xl shadow-orange-200">
                    <div className="flex items-start justify-between">
                        <div className="p-3 bg-white/20 rounded-2xl backdrop-blur-sm"><Icons.chart className="w-6 h-6" /></div>
                        <span className="text-orange-50 text-xs font-bold uppercase tracking-wider backdrop-blur-sm bg-white/10 px-2 py-1 rounded-lg">{L.labels.records}</span>
                    </div>
                    <div className="mt-6">
                        <div className="text-4xl font-bold tracking-tighter">{(stats.total_records || 0).toLocaleString()}</div>
                        <p className="text-orange-100/80 text-sm mt-1">{L.labels.totalRows}</p>
                    </div>
                </div>
            </div>

            {/* List */}
            <div className="grid gap-6">
                {sources.length === 0 ? (
                    <div className="text-center py-20 bg-slate-50 rounded-[2rem] border-2 border-dashed border-slate-200">
                        <div className="text-6xl mb-4 opacity-50 flex justify-center"><Icons.folderOpen className="w-16 h-16 text-slate-400" /></div>
                        <h3 className="text-xl font-bold text-slate-700">{L.empty.title}</h3>
                        <p className="text-slate-500 mb-6 max-w-md mx-auto mt-2">{L.empty.description}</p>
                        <Button onClick={() => router.push('/data-sources/create')}>{L.buttons.createSource}</Button>
                    </div>
                ) : (
                    sources.map((src) => (
                        <DataSourceCard
                            key={src.id}
                            source={src}
                            isExpanded={expandedId === src.id}
                            resources={expandedId === src.id ? resources : []}
                            loadingResources={loadingResources}
                            onToggleExpand={() => toggleExpand(src.id)}
                            onClone={() => handleClone(src.id)}
                            onDelete={() => setConfirmDialog({ id: src.id, name: src.name })}
                            onDeleteResource={(resourceId, resourceName) =>
                                setConfirmDialog({ id: resourceId, name: resourceName, type: 'resource', sourceId: src.id })
                            }
                            router={router}
                        />
                    ))
                )}
            </div>

            <ConfirmDialog
                isOpen={!!confirmDialog}
                onConfirm={handleDelete}
                onClose={() => setConfirmDialog(null)}
                variant="danger"
                title={confirmDialog?.type === 'resource'
                    ? `${C.actions.delete} Resource?`
                    : `${C.actions.delete} ${L.title}?`}
                message={confirmDialog?.type === 'resource'
                    ? L.messages.confirm.deleteResource
                    : L.messages.confirm.deleteSource}
                loading={submitting}
            />
        </div>
    );
};

// =============================================================================
// Sub-components (pure UI, receive all data via props)
