interface ResourceCardProps {
    resource: any;
    sourceId: number;
    onDelete: () => void;
    router: any;
}

const ResourceCard = ({ resource: r, sourceId, onDelete, router }: ResourceCardProps) => {
    const hasFilters = r.filters_json
        ? (JSON.parse(r.filters_json)?.filters?.length > 0 || (Array.isArray(JSON.parse(r.filters_json)) && JSON.parse(r.filters_json).length > 0))
        : false;
    const hasJoins = r.joins_json ? (JSON.parse(r.joins_json)?.length > 0) : false;

    return (
        <div
            className="group/card bg-white p-4 rounded-2xl border border-slate-200 hover:border-indigo-300 hover:shadow-lg hover:shadow-indigo-500/10 transition-all cursor-pointer relative"
            onClick={(e) => {
                e.stopPropagation();
                router.push(`/data-sources/${sourceId}/resources/${r.id}/edit`);
            }}
        >
            <div className="flex justify-between items-start mb-2">
                <div className="flex items-center gap-2">
                    <div className="w-10 h-10 rounded-xl bg-violet-50 text-violet-600 flex items-center justify-center text-lg font-bold">
                        {L.labels.httpGet}
                    </div>
                    {hasJoins && (
                        <div className="w-8 h-8 rounded-lg bg-orange-50 text-orange-600 flex items-center justify-center" title={L.labels.hasJoins}><Icons.link className="w-4 h-4" /></div>
                    )}
                </div>
                <Badge variant={r.is_public ? 'warning' : 'success'}>
                    {r.is_public ? L.labels.public : L.labels.protected}
                </Badge>
            </div>
            <h4 className="font-bold text-slate-800 mb-1 group-hover/card:text-indigo-600 transition-colors truncate" title={r.name}>{r.name}</h4>
            <div className="flex items-center gap-2 text-xs text-slate-400 font-mono bg-slate-50 px-2 py-1 rounded-lg w-fit mb-2">
                <span className="font-bold text-slate-300">/{r.slug}</span>
            </div>

            {/* Feature Badges */}
            <div className="flex gap-2">
                {hasFilters && <span className="text-[10px] font-bold bg-blue-50 text-blue-600 px-2 py-0.5 rounded-md">{L.labels.filters}</span>}
                <span className={`text-[10px] font-bold px-2 py-0.5 rounded-md ${r.is_active ? 'bg-emerald-50 text-emerald-600' : 'bg-slate-100 text-slate-400'}`}>
                    {r.is_active ? L.labels.active : L.labels.draft}
                </span>
            </div>

            <div className="absolute top-4 right-2 opacity-0 group-hover/card:opacity-100 transition-opacity flex gap-1">
                <button
                    className="p-2 hover:bg-slate-100 rounded-lg text-slate-400 hover:text-indigo-600 transition-colors"
                    onClick={(e) => {
                        e.stopPropagation();
                        router.push(`/data-sources/${sourceId}/resources/${r.id}/edit`);
                    }}
                >
                    <Icons.edit className="w-4 h-4" />
                </button>
                <button
                    className="p-2 hover:bg-red-50 rounded-lg text-slate-400 hover:text-red-500 transition-colors"
                    onClick={(e) => {
                        e.stopPropagation();
                        onDelete();
                    }}
                >
                    <Icons.delete className="w-4 h-4" />
                </button>
            </div>
        </div>
    );
};

'use client';

// DataViewer - Premium Responsive Table View for Data Sources
// Pure UI component - all operations delegated to useDataViewer composable

import { useState, useEffect, useMemo } from 'react';
import { Button, Badge } from '@repo/ui';
import { ConfirmDialog } from '@/modules/_core';
import { useDataViewer } from '../composables';
import type { DataSource } from '../types';
import { ImportDataModal } from './ImportDataModal';
import { API } from '../api';
import { Trash2, Download, Upload, RefreshCw } from 'lucide-react';

interface DataViewerProps {
    dataSource: DataSource;
}

export const DataViewer = ({ dataSource }: DataViewerProps) => {
    // All data operations from composable
    const {
        rows,
        loading,
        total,
        pagination,
        sorting,
        selection,
        fetchData,
        deleteRow,
        deleteSelected,
    } = useDataViewer(dataSource.id);

    // UI-only state
    const [confirmDelete, setConfirmDelete] = useState<any | null>(null);
    const [isImportOpen, setIsImportOpen] = useState(false);
    const [bulkDeleting, setBulkDeleting] = useState(false);

    const columns = dataSource.schema?.columns || [];
    const totalPages = Math.ceil(total / pagination.limit) || 1;

    // Fetch data when dependencies change
    useEffect(() => {
        fetchData();
        selection.deselectAll();
    }, [dataSource.id, pagination.page, pagination.limit, sorting.sortColumn, sorting.sortDirection]);

    // UI Handlers - delegate to composable
    const handleSort = (colName: string) => {
        sorting.handleSort(colName);
    };

    const handleDelete = async () => {
        if (!confirmDelete) return;
        await deleteRow(confirmDelete.id);
        setConfirmDelete(null);
    };

    const handleBulkDelete = async () => {
        if (selection.selectedCount === 0) return;
        if (!confirm(`Are you sure you want to delete ${selection.selectedCount} rows?`)) return;

        setBulkDeleting(true);
        await deleteSelected();
        setBulkDeleting(false);
    };

    // Mobile Card View Component (pure UI)
    const MobileCardView = ({ row, index }: { row: any; index: number }) => (
        <div
            className={`p-4 border-b border-slate-100 last:border-b-0 ${selection.isSelected(row.id) ? 'bg-indigo-50/30' : ''}`}
        >
            <div className="flex items-start justify-between gap-3 mb-3">
                <div className="flex items-center gap-3">
                    <input
                        type="checkbox"
                        checked={selection.isSelected(row.id)}
                        onChange={() => selection.toggle(row.id)}
                        className="rounded border-slate-300 text-indigo-600 focus:ring-indigo-500"
                    />
                    <span className="text-xs font-mono text-slate-400 bg-slate-100 px-2 py-1 rounded">
                        ID: {row.id}
                    </span>
                </div>
                <button
                    onClick={() => setConfirmDelete(row)}
                    className="text-slate-400 hover:text-red-500 hover:bg-red-50 p-2 rounded-lg transition-colors"
                >
                    <Trash2 className="w-4 h-4" />
                </button>
            </div>
            <div className="space-y-2">
                {columns.slice(0, 5).map(col => (
                    <div key={col.name} className="flex flex-col">
                        <span className="text-xs text-slate-400 font-medium uppercase tracking-wide">
                            {col.name}
                        </span>
                        <span className="text-sm text-slate-700 break-words">
                            {typeof row[col.name] === 'object'
                                ? JSON.stringify(row[col.name])
                                : String(row[col.name] || '-')
                            }
                        </span>
                    </div>
                ))}
                {columns.length > 5 && (
                    <div className="text-xs text-slate-400 italic pt-2">
                        +{columns.length - 5} more fields...
                    </div>
                )}
            </div>
        </div>
    );

    return (
        <div className="bg-white rounded-[2rem] border border-slate-100 shadow-sm overflow-hidden animate-in fade-in slide-in-from-bottom-4 duration-500 w-full max-w-full">
            {/* Header */}
            <div className="p-4 sm:p-6 border-b border-slate-100 flex flex-col sm:flex-row sm:items-center justify-between gap-4 bg-slate-50/30">
                <div className="flex items-center gap-3">
                    <div className="w-10 h-10 rounded-xl bg-teal-50 text-teal-600 flex items-center justify-center text-xl">
                        ≡ƒôè
                    </div>
                    <div>
                        <h3 className="font-bold text-slate-800">Data Preview</h3>
                        <p className="text-xs text-slate-500">View and manage table rows</p>
                    </div>
                </div>
                <div className="flex flex-wrap gap-2">
                    {selection.selectedCount > 0 && (
                        <Button size="sm" variant="danger" onClick={handleBulkDelete} isLoading={bulkDeleting} className="gap-2">
                            <Trash2 className="w-4 h-4" /> Delete ({selection.selectedCount})
                        </Button>
                    )}
                    <Button size="sm" variant="outline" onClick={() => window.open(`${API.list}/${dataSource.id}/export?format=csv`, '_blank')} className="gap-1">
                        <Download className="w-4 h-4 hidden sm:inline" /> Export
                    </Button>
                    <Button size="sm" variant="outline" onClick={() => setIsImportOpen(true)} className="gap-1">
                        <Upload className="w-4 h-4 hidden sm:inline" /> Import
                    </Button>
                    <Button size="sm" variant="slate" onClick={fetchData} isLoading={loading}>
                        <RefreshCw className={`w-4 h-4 ${loading ? 'animate-spin' : ''}`} />
                    </Button>
                </div>
            </div>

            {/* Desktop Table View */}
            <div className="hidden md:block overflow-x-auto">
                <table className="w-full text-sm text-left">
                    <thead className="bg-slate-50 text-slate-500 font-medium border-b border-slate-100">
                        <tr>
                            <th className="px-6 py-4 w-12 text-center">
                                <input
                                    type="checkbox"
                                    checked={rows.length > 0 && selection.selectedCount === rows.length}
                                    onChange={() => selection.toggleAll(rows)}
                                    className="rounded border-slate-300 text-indigo-600 focus:ring-indigo-500"
                                />
                            </th>
                            <th className="px-6 py-4 w-16">ID</th>
                            {columns.slice(0, 5).map(col => (
                                <th
                                    key={col.name}
                                    className="px-6 py-4 cursor-pointer hover:text-indigo-600 transition-colors group"
                                    onClick={() => handleSort(col.name)}
                                >
                                    <div className="flex items-center gap-1">
                                        {col.name}
                                        {sorting.sortColumn === col.name && (
                                            <span className="text-xs text-indigo-500">
                                                {sorting.getSortIcon(col.name)}
                                            </span>
                                        )}
                                    </div>
                                </th>
                            ))}
                            {columns.length > 5 && <th className="px-6 py-4 text-slate-400">...</th>}
                            <th className="px-6 py-4 text-right">Actions</th>
                        </tr>
                    </thead>
                    <tbody className="divide-y divide-slate-50">
                        {loading && rows.length === 0 ? (
                            <tr>
                                <td colSpan={100} className="p-12 text-center text-slate-400">
                                    <div className="inline-block animate-spin rounded-full h-8 w-8 border-b-2 border-indigo-600"></div>
                                </td>
                            </tr>
                        ) : rows.length === 0 ? (
                            <tr>
                                <td colSpan={100} className="p-12 text-center text-slate-400">
                                    No data found in this table.
                                </td>
                            </tr>
                        ) : (
                            rows.map((row, i) => (
                                <tr key={row.id || i} className={`hover:bg-slate-50/50 transition-colors group ${selection.isSelected(row.id) ? 'bg-indigo-50/30' : ''}`}>
                                    <td className="px-6 py-4 text-center">
                                        <input
                                            type="checkbox"
                                            checked={selection.isSelected(row.id)}
                                            onChange={() => selection.toggle(row.id)}
                                            className="rounded border-slate-300 text-indigo-600 focus:ring-indigo-500"
                                        />
                                    </td>
                                    <td className="px-6 py-4 font-mono text-slate-400">{row.id}</td>
                                    {columns.slice(0, 5).map(col => (
                                        <td key={col.name} className="px-6 py-4 max-w-[200px] truncate text-slate-700">
                                            {typeof row[col.name] === 'object'
                                                ? JSON.stringify(row[col.name])
                                                : String(row[col.name] || '-')
                                            }
                                        </td>
                                    ))}
                                    {columns.length > 5 && <td className="px-6 py-4 text-slate-400">...</td>}
                                    <td className="px-6 py-4 text-right opacity-0 group-hover:opacity-100 transition-opacity">
                                        <button
                                            onClick={() => setConfirmDelete(row)}
                                            className="text-slate-400 hover:text-red-500 hover:bg-red-50 p-2 rounded-lg transition-colors"
                                        >
                                            <Trash2 className="w-4 h-4" />
                                        </button>
                                    </td>
                                </tr>
                            ))
                        )}
                    </tbody>
                </table>
            </div>

            {/* Mobile Card View */}
            <div className="md:hidden">
                {loading && rows.length === 0 ? (
                    <div className="p-12 text-center text-slate-400">
                        <div className="inline-block animate-spin rounded-full h-8 w-8 border-b-2 border-indigo-600"></div>
                    </div>
                ) : rows.length === 0 ? (
                    <div className="p-12 text-center text-slate-400">
                        No data found in this table.
                    </div>
                ) : (
                    <>
                        {/* Mobile Select All Header */}
                        <div className="p-3 bg-slate-50 border-b border-slate-100 flex items-center gap-3">
                            <input
                                type="checkbox"
                                checked={rows.length > 0 && selection.selectedCount === rows.length}
                                onChange={() => selection.toggleAll(rows)}
                                className="rounded border-slate-300 text-indigo-600 focus:ring-indigo-500"
                            />
                            <span className="text-xs text-slate-500">
                                {selection.selectedCount > 0 ? `${selection.selectedCount} selected` : 'Select all'}
                            </span>
                        </div>
                        {rows.map((row, i) => (
                            <MobileCardView key={row.id || i} row={row} index={i} />
                        ))}
                    </>
                )}
            </div>

            {/* Pagination */}
            {totalPages >= 1 && (
                <div className="p-4 border-t border-slate-100 flex flex-col sm:flex-row items-center justify-between gap-4 bg-slate-50/30">
                    <div className="text-xs text-slate-500 flex items-center gap-2">
                        <span>Rows:</span>
                        <select
                            value={pagination.limit}
                            onChange={(e) => pagination.setLimit(Number(e.target.value))}
                            className="bg-transparent border border-slate-200 rounded px-2 py-1 focus:outline-none focus:border-indigo-500"
                        >
                            <option value={10}>10</option>
                            <option value={20}>20</option>
                            <option value={50}>50</option>
                            <option value={100}>100</option>
                        </select>
                        <span className="hidden sm:inline text-slate-300">|</span>
                        <span className="hidden sm:inline">
                            {Math.min((pagination.page - 1) * pagination.limit + 1, total)}-{Math.min(pagination.page * pagination.limit, total)} of {total}
                        </span>
                    </div>
                    <div className="flex items-center gap-2">
                        <Button
                            size="sm"
                            variant="slate"
                            disabled={pagination.page === 1}
                            onClick={() => pagination.setPage(pagination.page - 1)}
                        >
                            <span className="hidden sm:inline">Previous</span>
                            <span className="sm:hidden">ΓåÉ</span>
                        </Button>
                        <div className="flex items-center gap-1">
                            <span className="text-xs text-slate-400">Page</span>
                            <input
                                type="number"
                                min={1}
                                max={totalPages}
                                value={pagination.page}
                                onChange={(e) => {
                                    const val = parseInt(e.target.value);
                                    if (!isNaN(val) && val >= 1 && val <= totalPages) {
                                        pagination.setPage(val);
                                    }
                                }}
                                className="w-12 h-7 text-center text-xs border border-slate-200 rounded focus:border-indigo-500 focus:outline-none"
                            />
                            <span className="text-xs text-slate-400">/ {totalPages}</span>
                        </div>
                        <Button
                            size="sm"
                            variant="slate"
                            disabled={pagination.page === totalPages}
                            onClick={() => pagination.setPage(pagination.page + 1)}
                        >
                            <span className="hidden sm:inline">Next</span>
                            <span className="sm:hidden">ΓåÆ</span>
                        </Button>
                    </div>
                </div>
            )}

            <ConfirmDialog
                isOpen={!!confirmDelete}
                onClose={() => setConfirmDelete(null)}
                onConfirm={handleDelete}
                title="Delete Row"
                message="Are you sure you want to delete this record? This action cannot be undone."
                variant="danger"
            />

            <ImportDataModal
                isOpen={isImportOpen}
                onClose={() => setIsImportOpen(false)}
                dataSourceId={dataSource.id}
                onSuccess={fetchData}
            />
        </div>
    );
};

import React, { useState } from 'react';
import { Button } from '@repo/ui';
import { useImportData } from '../composables';

interface ImportDataModalProps {
    isOpen: boolean;
    onClose: () => void;
    dataSourceId: number;
    onSuccess: () => void;
}

export function ImportDataModal({
    isOpen,
    onClose,
    dataSourceId,
    onSuccess
}: ImportDataModalProps) {
    const [inputData, setInputData] = useState('');
    const { importing, error, importData } = useImportData(dataSourceId);

    if (!isOpen) return null;

    const handleImport = async () => {
        try {
            const parsedData = JSON.parse(inputData);
            const success = await importData(parsedData);
            if (success) {
                onSuccess();
                onClose();
                setInputData('');
            }
        } catch (e) {
            // JSON parse error is handled internally
        }
    };

    return (
        <div className="fixed inset-0 bg-slate-900/60 backdrop-blur-sm z-[200] flex items-center justify-center p-4 animate-in fade-in duration-200">
            <div className="bg-white w-full max-w-2xl rounded-[2rem] p-8 shadow-2xl animate-in zoom-in-95 duration-300">
                <div className="flex flex-col">
                    <div className="flex items-center justify-between mb-6">
                        <h2 className="text-xl font-bold text-slate-900">Import Data (Bulk Insert)</h2>
                        <button onClick={onClose} className="text-slate-400 hover:text-slate-600 transition-colors">
                            <svg xmlns="http://www.w3.org/2000/svg" width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><line x1="18" y1="6" x2="6" y2="18"></line><line x1="6" y1="6" x2="18" y2="18"></line></svg>
                        </button>
                    </div>

                    <div className="space-y-4 mb-8">
                        <div className="space-y-2">
                            <label htmlFor="json-input" className="text-sm font-medium text-slate-700">JSON Data (Array of Objects)</label>
                            <textarea
                                id="json-input"
                                placeholder='[{"name": "John", "email": "john@example.com"}, ...]'
                                className="w-full h-[300px] font-mono text-sm p-4 rounded-xl border border-slate-200 focus:border-indigo-500 focus:ring-2 focus:ring-indigo-200 outline-none transition-all resize-none"
                                value={inputData}
                                onChange={(e) => setInputData(e.target.value)}
                            />
                        </div>
                        {error && <p className="text-sm text-red-500 bg-red-50 p-3 rounded-lg border border-red-100">{error}</p>}
                    </div>

                    <div className="flex justify-end gap-3">
                        <Button variant="slate" onClick={onClose} disabled={importing}>
                            Cancel
                        </Button>
                        <Button onClick={handleImport} disabled={importing || !inputData.trim()} isLoading={importing}>
                            Import Data
                        </Button>
                    </div>
                </div>
            </div>
        </div>
    );
}

'use client';

// RelationBuilder - Component for managing data source relations
// Pure UI component - all data operations via useRelations composable

import { useState } from 'react';
import { Button, Badge } from '@repo/ui';
import { ConfirmDialog } from '@/modules/_core';
import { useRelations, type Relation } from '../composables';
import { RELATION_TYPES } from '../registry';
import { Link2, Unlink, ArrowRight, Plus, Trash2 } from 'lucide-react';

interface RelationBuilderProps {
    dataSourceId: number;
    dataSourceName: string;
    onRelationsChange?: () => void;
}

export const RelationBuilder = ({ dataSourceId, dataSourceName, onRelationsChange }: RelationBuilderProps) => {
    // All data operations from composable
    const {
        relations,
        targets,
        loading,
        adding,
        addRelation,
        deleteRelation,
    } = useRelations(dataSourceId);

    // UI-only state
    const [showAddModal, setShowAddModal] = useState(false);
    const [deleteTarget, setDeleteTarget] = useState<Relation | null>(null);
    const [newRelation, setNewRelation] = useState({
        targetId: 0,
        type: 'belongs_to' as Relation['type'],
        alias: '',
    });

    // Handle add relation
    const handleAddRelation = async () => {
        const result = await addRelation(newRelation);
        if (result) {
            setShowAddModal(false);
            setNewRelation({ targetId: 0, type: 'belongs_to', alias: '' });
            onRelationsChange?.();
        }
    };

    // Handle delete relation
    const handleDeleteRelation = async () => {
        if (!deleteTarget) return;
        const success = await deleteRelation(deleteTarget.id);
        if (success) {
            setDeleteTarget(null);
            onRelationsChange?.();
        }
    };

    const getTypeLabel = (type: string) => RELATION_TYPES.find(t => t.value === type)?.label || type;
    const getTypeIcon = (type: string) => RELATION_TYPES.find(t => t.value === type)?.icon || '?';

    if (loading) {
        return (
            <div className="p-6 text-center text-slate-400">
                <div className="animate-spin w-6 h-6 border-2 border-slate-300 border-t-slate-600 rounded-full mx-auto"></div>
                <p className="mt-2 text-sm">Loading relations...</p>
            </div>
        );
    }

    return (
        <div className="space-y-4">
            {/* Header */}
            <div className="flex items-center justify-between">
                <div className="flex items-center gap-2">
                    <Link2 className="w-5 h-5 text-indigo-500" />
                    <h3 className="font-bold text-slate-800">Relations</h3>
                    <Badge variant="slate">{relations.length}</Badge>
                </div>
                <Button size="sm" onClick={() => setShowAddModal(true)} className="gap-2">
                    <Plus className="w-4 h-4" /> Add Relation
                </Button>
            </div>

            {/* Relations List */}
            {relations.length === 0 ? (
                <div className="p-8 text-center bg-slate-50 rounded-xl border-2 border-dashed border-slate-200">
                    <Unlink className="w-10 h-10 text-slate-300 mx-auto mb-3" />
                    <p className="text-slate-500 font-medium">No relations defined</p>
                    <p className="text-slate-400 text-sm mt-1">Add a relation to link this data source to others</p>
                </div>
            ) : (
                <div className="space-y-2">
                    {relations.map(rel => (
                        <div
                            key={rel.id}
                            className="flex items-center justify-between p-4 bg-white rounded-xl border border-slate-100 hover:border-indigo-200 hover:shadow-sm transition-all"
                        >
                            <div className="flex items-center gap-4">
                                {/* Type Badge */}
                                <div className={`
                                    w-10 h-10 rounded-xl flex items-center justify-center text-lg font-bold
                                    ${rel.type === 'belongs_to' ? 'bg-blue-100 text-blue-600' : ''}
                                    ${rel.type === 'has_one' ? 'bg-green-100 text-green-600' : ''}
                                    ${rel.type === 'has_many' ? 'bg-amber-100 text-amber-600' : ''}
                                    ${rel.type === 'many_to_many' ? 'bg-purple-100 text-purple-600' : ''}
                                `}>
                                    {getTypeIcon(rel.type)}
                                </div>

                                {/* Relation Info */}
                                <div>
                                    <div className="flex items-center gap-2">
                                        <span className="font-bold text-slate-700">{dataSourceName}</span>
                                        <ArrowRight className="w-4 h-4 text-slate-400" />
                                        <span className="font-bold text-indigo-600">{rel.target?.name || 'Unknown'}</span>
                                    </div>
                                    <div className="flex items-center gap-2 mt-1 text-xs text-slate-500">
                                        <Badge variant="slate" className="text-[10px]">{getTypeLabel(rel.type)}</Badge>
                                        {rel.localKey && <span>FK: <code className="bg-slate-100 px-1 rounded">{rel.localKey}</code></span>}
                                        {rel.pivotTable && <span>Pivot: <code className="bg-slate-100 px-1 rounded">{rel.pivotTable}</code></span>}
                                        <span>as <code className="bg-indigo-50 text-indigo-600 px-1 rounded">{rel.alias}</code></span>
                                    </div>
                                </div>
                            </div>

                            {/* Actions */}
                            <button
                                onClick={() => setDeleteTarget(rel)}
                                className="p-2 rounded-lg text-slate-400 hover:text-red-500 hover:bg-red-50 transition-colors"
                            >
                                <Trash2 className="w-5 h-5" />
                            </button>
                        </div>
                    ))}
                </div>
            )}

            {/* Add Modal */}
            {showAddModal && (
                <div className="fixed inset-0 bg-black/50 backdrop-blur-sm z-50 flex items-center justify-center p-4">
                    <div className="bg-white rounded-2xl shadow-xl w-full max-w-md animate-in fade-in slide-in-from-bottom-4">
                        <div className="p-6 border-b border-slate-100">
                            <h3 className="text-lg font-bold text-slate-800">Add Relation</h3>
                            <p className="text-sm text-slate-500 mt-1">Create a relationship to another data source</p>
                        </div>

                        <div className="p-6 space-y-4">
                            {/* Target Selection */}
                            <div>
                                <label className="block text-xs font-bold uppercase text-slate-400 mb-2">Target Table</label>
                                <select
                                    value={newRelation.targetId}
                                    onChange={(e) => setNewRelation(prev => ({ ...prev, targetId: parseInt(e.target.value) }))}
                                    className="w-full px-3 py-2 rounded-lg border border-slate-200 focus:border-indigo-500 focus:ring-2 focus:ring-indigo-200 outline-none"
                                >
                                    <option value={0}>Select a table...</option>
                                    {targets.map(t => (
                                        <option key={t.id} value={t.id}>
                                            {t.name} ({t.tableName})
                                        </option>
                                    ))}
                                </select>
                            </div>

                            {/* Relation Type */}
                            <div>
                                <label className="block text-xs font-bold uppercase text-slate-400 mb-2">Relation Type</label>
                                <div className="grid grid-cols-2 gap-2">
                                    {RELATION_TYPES.map(type => (
                                        <button
                                            key={type.value}
                                            type="button"
                                            onClick={() => setNewRelation(prev => ({ ...prev, type: type.value as Relation['type'] }))}
                                            className={`
                                                p-3 rounded-xl border-2 text-left transition-all
                                                ${newRelation.type === type.value
                                                    ? 'border-indigo-500 bg-indigo-50'
                                                    : 'border-slate-200 hover:border-slate-300'}
                                            `}
                                        >
                                            <div className="flex items-center gap-2">
                                                <span className="text-lg">{type.icon}</span>
                                                <span className="font-bold text-sm text-slate-700">{type.label}</span>
                                            </div>
                                            <p className="text-[10px] text-slate-500 mt-1">{type.desc}</p>
                                        </button>
                                    ))}
                                </div>
                            </div>

                            {/* Alias */}
                            <div>
                                <label className="block text-xs font-bold uppercase text-slate-400 mb-2">Alias (optional)</label>
                                <input
                                    type="text"
                                    value={newRelation.alias}
                                    onChange={(e) => setNewRelation(prev => ({ ...prev, alias: e.target.value }))}
                                    placeholder="e.g., user, tags, profile"
                                    className="w-full px-3 py-2 rounded-lg border border-slate-200 focus:border-indigo-500 focus:ring-2 focus:ring-indigo-200 outline-none"
                                />
                                <p className="text-xs text-slate-400 mt-1">This name will be used in API responses</p>
                            </div>
                        </div>

                        <div className="p-6 border-t border-slate-100 flex justify-end gap-2">
                            <Button variant="ghost" onClick={() => setShowAddModal(false)}>Cancel</Button>
                            <Button onClick={handleAddRelation} isLoading={adding}>Add Relation</Button>
                        </div>
                    </div>
                </div>
            )}

            {/* Delete Confirmation */}
            <ConfirmDialog
                isOpen={!!deleteTarget}
                onClose={() => setDeleteTarget(null)}
                onConfirm={handleDeleteRelation}
                title="Delete Relation?"
                message={`This will remove the relation to "${deleteTarget?.target?.name}". ${deleteTarget?.type === 'belongs_to' ? 'The FK column will be dropped.' : ''
                    }${deleteTarget?.type === 'many_to_many' ? 'The pivot table will be dropped.' : ''
                    }`}
                confirmText="Delete"
                variant="danger"
            />
        </div>
    );
};

export default RelationBuilder;

'use client';

// ResourceEditor - Component for creating/editing API resources
// Pure UI component - all data operations via composables

import { useState, useEffect } from 'react';
import { Button, Badge } from '@repo/ui';
import { Icons } from '@/modules/_core';
import { useResourceSubmit, useRelations, type ResourcePayload, type Relation } from '../composables';
import { DEFAULTS } from '../config';
import type { DataSource, Resource, ColumnDefinition } from '../types';
import { Link2, ChevronDown, ChevronUp } from 'lucide-react';

interface IncludedRelation {
    relationId: number;
    alias: string;
    fields: string[];
}

interface ResourceEditorProps {
    dataSource: DataSource;
    resource?: Resource;
    onSave: () => void;
    onCancel: () => void;
}

// Parse JSON safely
const safeParseJSON = <T,>(json: string | undefined | null, fallback: T): T => {
    if (!json) return fallback;
    try {
        return JSON.parse(json);
    } catch {
        return fallback;
    }
};

// Filter type
interface FilterItem {
    field: string;
    operator: '=' | '!=' | '>' | '<' | '>=' | '<=' | 'LIKE' | 'NOT LIKE' | 'IN' | 'NOT IN';
    value: string;
}

export const ResourceEditor = ({ dataSource, resource, onSave, onCancel }: ResourceEditorProps) => {
    // All data operations from composables
    const { submitting, create, update } = useResourceSubmit(dataSource.id);
    const { relations, loading: relationsLoading } = useRelations(dataSource.id);

    // UI state for relations section
    const [includedRelations, setIncludedRelations] = useState<IncludedRelation[]>(
        safeParseJSON(resource?.relationsJson, [])
    );
    const [showRelations, setShowRelations] = useState(false);

    // Form State
    const [form, setForm] = useState<{
        name: string;
        slug: string;
        description: string;
        fields: string[];
        filters: FilterItem[];
        filterLogic: 'AND' | 'OR';
        orderBy: string;
        orderDirection: 'ASC' | 'DESC';
        limit: number;
        isPublic: boolean;
    }>({
        name: resource?.name || '',
        slug: resource?.slug || '',
        description: resource?.description || '',
        fields: safeParseJSON(resource?.fieldsJson, []),
        filters: safeParseJSON(resource?.filtersJson, []),
        filterLogic: 'AND',
        orderBy: resource?.orderBy || DEFAULTS.resourceForm.orderBy,
        orderDirection: resource?.orderDirection || DEFAULTS.resourceForm.orderDirection,
        limit: resource?.defaultLimit || DEFAULTS.resourceForm.defaultLimit,
        isPublic: resource?.isPublic || DEFAULTS.resourceForm.isPublic,
    });

    const columns = dataSource.schema?.columns || [];

    // Toggle relation inclusion
    const toggleRelation = (rel: Relation) => {
        setIncludedRelations(prev => {
            const exists = prev.find(r => r.relationId === rel.id);
            if (exists) {
                return prev.filter(r => r.relationId !== rel.id);
            }
            return [...prev, { relationId: rel.id, alias: rel.alias, fields: [] }];
        });
    };

    const isRelationIncluded = (relId: number) => {
        return includedRelations.some(r => r.relationId === relId);
    };

    // Filter management
    const addFilter = () => {
        if (columns.length === 0) return;
        setForm(prev => ({
            ...prev,
            filters: [...prev.filters, { field: columns[0].name, operator: '=', value: '' }]
        }));
    };

    const updateFilter = (index: number, key: keyof FilterItem, value: string) => {
        setForm(prev => {
            const newFilters = [...prev.filters];
            newFilters[index] = { ...newFilters[index], [key]: value };
            return { ...prev, filters: newFilters };
        });
    };

    const removeFilter = (index: number) => {
        setForm(prev => ({
            ...prev,
            filters: prev.filters.filter((_, i) => i !== index)
        }));
    };

    // Auto-generate slug from name
    const handleNameChange = (val: string) => {
        const updates: any = { name: val };
        if (!resource && !form.slug && val) {
            updates.slug = val.toLowerCase().replace(/[^a-z0-9]+/g, '-').replace(/^-+|-+$/g, '');
        }
        setForm(prev => ({ ...prev, ...updates }));
    };

    const toggleField = (colName: string) => {
        setForm(prev => {
            const exists = prev.fields.includes(colName);
            if (exists) return { ...prev, fields: prev.fields.filter(f => f !== colName) };
            return { ...prev, fields: [...prev.fields, colName] };
        });
    };

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();

        const payload: ResourcePayload = {
            data_source_id: dataSource.id,
            name: form.name,
            slug: form.slug,
            description: form.description,
            fields_json: JSON.stringify(form.fields),
            filters_json: JSON.stringify(form.filters),
            relations_json: JSON.stringify(includedRelations),
            order_by: form.orderBy,
            order_direction: form.orderDirection,
            default_limit: form.limit,
            is_public: form.isPublic,
        };

        const result = resource
            ? await update(resource.id, payload)
            : await create(payload);

        if (result) {
            onSave();
        }
    };

    return (
        <form onSubmit={handleSubmit} className="space-y-6 animate-in fade-in slide-in-from-bottom-2">

            {/* Header / Info */}
            <div className="bg-indigo-50/50 p-4 rounded-xl border border-indigo-100 flex items-start gap-3">
                <div className="text-indigo-600"><Icons.radio className="w-6 h-6" /></div>
                <div>
                    <h3 className="font-bold text-indigo-900">
                        {resource ? 'Edit API Resource' : 'Create API Resource'}
                    </h3>
                    <p className="text-sm text-indigo-600/80">
                        Endpoints allow external access to your data. Configure fields and security below.
                    </p>
                </div>
            </div>

            {/* Basic Info */}
            <div className="grid md:grid-cols-2 gap-4">
                <div>
                    <label className="block text-xs font-bold uppercase text-slate-400 mb-1">Resource Name</label>
                    <input
                        type="text"
                        value={form.name}
                        onChange={(e) => handleNameChange(e.target.value)}
                        placeholder="e.g. Active Products"
                        className="w-full px-3 py-2 rounded-lg border border-slate-200 focus:border-[var(--primary)] focus:ring-2 focus:ring-[var(--primary)]/20 outline-none transition-all"
                    />
                </div>
                <div>
                    <label className="block text-xs font-bold uppercase text-slate-400 mb-1">URL Slug</label>
                    <div className="flex items-center">
                        <span className="bg-slate-100 px-3 py-2 border border-r-0 border-slate-200 rounded-l-lg text-slate-500 text-sm">/api/</span>
                        <input
                            type="text"
                            value={form.slug}
                            onChange={(e) => setForm({ ...form, slug: e.target.value.toLowerCase().replace(/[^a-z0-9-]+/g, '') })}
                            placeholder="active-products"
                            className="w-full px-3 py-2 rounded-r-lg border border-slate-200 focus:border-[var(--primary)] focus:ring-2 focus:ring-[var(--primary)]/20 outline-none transition-all"
                        />
                    </div>
                </div>
                <div className="md:col-span-2">
                    <label className="block text-xs font-bold uppercase text-slate-400 mb-1">Description</label>
                    <input
                        type="text"
                        value={form.description}
                        onChange={(e) => setForm({ ...form, description: e.target.value })}
                        placeholder="Internal notes about this endpoint"
                        className="w-full px-3 py-2 rounded-lg border border-slate-200 focus:border-[var(--primary)] focus:ring-2 focus:ring-[var(--primary)]/20 outline-none transition-all"
                    />
                </div>
            </div>

            {/* Field Selection */}
            <div>
                <label className="block text-xs font-bold uppercase text-slate-400 mb-2">
                    Response Fields
                    <Badge variant="slate" className="ml-2">{form.fields.length > 0 ? form.fields.length : 'All'} selected</Badge>
                </label>
                <div className="p-4 bg-slate-50 rounded-xl border border-slate-100 max-h-48 overflow-y-auto custom-scrollbar">
                    <div className="flex flex-wrap gap-2">
                        {columns.length === 0 && <span className="text-slate-400 text-sm">No columns available</span>}
                        {columns.map(col => {
                            const isSelected = form.fields.length === 0 || form.fields.includes(col.name);
                            return (
                                <button
                                    key={col.name}
                                    type="button"
                                    onClick={() => toggleField(col.name)}
                                    className={`
                                        px-3 py-1.5 rounded-lg text-sm font-medium border transition-all flex items-center gap-2
                                        ${isSelected
                                            ? 'bg-white border-indigo-200 text-indigo-700 shadow-sm'
                                            : 'bg-slate-100 border-transparent text-slate-400 opacity-60 hover:opacity-100'
                                        }
                                    `}
                                >
                                    {isSelected && <Icons.check className="w-4 h-4 text-indigo-500" />}
                                    {col.name}
                                </button>
                            );
                        })}
                    </div>
                    {form.fields.length === 0 && (
                        <p className="text-xs text-slate-400 mt-2 italic text-center">
                            Empty selection returns <strong>ALL</strong> columns by default.
                        </p>
                    )}
                </div>
            </div>

            {/* Filter Builder */}
            <div>
                <label className="block text-xs font-bold uppercase text-slate-400 mb-2">
                    Data Filters (WHERE clause)
                    <Badge variant="slate" className="ml-2">{form.filters.length} conditions</Badge>
                </label>
                <div className="p-4 bg-amber-50/50 rounded-xl border border-amber-100 space-y-3">
                    {form.filters.length === 0 && (
                        <p className="text-xs text-amber-600 italic text-center">No filters. All rows will be returned.</p>
                    )}

                    {form.filters.map((filter, idx) => (
                        <div key={idx} className="flex items-center gap-2 flex-wrap">
                            {idx > 0 && (
                                <span className="text-xs font-bold text-amber-600 w-10">{form.filterLogic}</span>
                            )}
                            <select
                                value={filter.field}
                                onChange={(e) => updateFilter(idx, 'field', e.target.value)}
                                className="flex-1 min-w-[100px] px-2 py-1.5 rounded-lg border border-slate-200 text-sm bg-white"
                            >
                                {columns.map(col => (
                                    <option key={col.name} value={col.name}>{col.name}</option>
                                ))}
                            </select>
                            <select
                                value={filter.operator}
                                onChange={(e) => updateFilter(idx, 'operator', e.target.value)}
                                className="w-24 px-2 py-1.5 rounded-lg border border-slate-200 text-sm bg-white"
                            >
                                <option value="=">=</option>
                                <option value="!=">!=</option>
                                <option value=">">&gt;</option>
                                <option value="<">&lt;</option>
                                <option value=">=">&gt;=</option>
                                <option value="<=">&lt;=</option>
                                <option value="LIKE">LIKE</option>
                                <option value="NOT LIKE">NOT LIKE</option>
                                <option value="IN">IN</option>
                                <option value="NOT IN">NOT IN</option>
                            </select>
                            <input
                                type="text"
                                value={filter.value}
                                onChange={(e) => updateFilter(idx, 'value', e.target.value)}
                                placeholder="Value..."
                                className="flex-1 min-w-[100px] px-2 py-1.5 rounded-lg border border-slate-200 text-sm"
                            />
                            <button
                                type="button"
                                onClick={() => removeFilter(idx)}
                                className="w-7 h-7 rounded-lg bg-red-50 text-red-500 hover:bg-red-100 flex items-center justify-center"
                            >
                                <Icons.close className="w-4 h-4" />
                            </button>
                        </div>
                    ))}

                    <div className="flex items-center justify-between pt-2 border-t border-amber-100">
                        <div className="flex items-center gap-2">
                            <span className="text-xs text-slate-500">Logic:</span>
                            <button
                                type="button"
                                onClick={() => setForm(prev => ({ ...prev, filterLogic: 'AND' }))}
                                className={`px-2 py-1 rounded text-xs font-bold ${form.filterLogic === 'AND' ? 'bg-amber-200 text-amber-800' : 'bg-white text-slate-400'}`}
                            >
                                AND
                            </button>
                            <button
                                type="button"
                                onClick={() => setForm(prev => ({ ...prev, filterLogic: 'OR' }))}
                                className={`px-2 py-1 rounded text-xs font-bold ${form.filterLogic === 'OR' ? 'bg-amber-200 text-amber-800' : 'bg-white text-slate-400'}`}
                            >
                                OR
                            </button>
                        </div>
                        <button
                            type="button"
                            onClick={addFilter}
                            className="px-3 py-1 rounded-lg bg-amber-200 text-amber-800 text-xs font-bold hover:bg-amber-300 transition-colors"
                        >
                            + Add Filter
                        </button>
                    </div>
                </div>
            </div>

            {/* Include Relations */}
            {relations.length > 0 && (
                <div className="bg-indigo-50/50 p-4 rounded-xl border border-indigo-100">
                    <button
                        type="button"
                        onClick={() => setShowRelations(!showRelations)}
                        className="w-full flex items-center justify-between"
                    >
                        <div className="flex items-center gap-2">
                            <Link2 className="w-5 h-5 text-indigo-600" />
                            <span className="font-bold text-indigo-900">Include Relations</span>
                            <Badge variant="slate">{includedRelations.length} / {relations.length}</Badge>
                        </div>
                        {showRelations ? <ChevronUp className="w-5 h-5 text-indigo-600" /> : <ChevronDown className="w-5 h-5 text-indigo-600" />}
                    </button>

                    {showRelations && (
                        <div className="mt-4 space-y-2">
                            <p className="text-xs text-indigo-600 mb-3">Select relations to include in API response</p>
                            {relations.map(rel => (
                                <label
                                    key={rel.id}
                                    className={`flex items-center gap-3 p-3 rounded-lg border cursor-pointer transition-all ${isRelationIncluded(rel.id)
                                        ? 'bg-white border-indigo-300 shadow-sm'
                                        : 'bg-indigo-50/50 border-indigo-100 hover:border-indigo-200'
                                        }`}
                                >
                                    <input
                                        type="checkbox"
                                        checked={isRelationIncluded(rel.id)}
                                        onChange={() => toggleRelation(rel)}
                                        className="w-4 h-4 rounded text-indigo-600 focus:ring-indigo-500"
                                    />
                                    <div className="flex-1">
                                        <span className="font-medium text-slate-700">{rel.target?.name || 'Unknown'}</span>
                                        <span className="text-xs text-slate-500 ml-2">as <code className="bg-indigo-100 text-indigo-600 px-1 rounded">{rel.alias}</code></span>
                                    </div>
                                    <Badge variant="slate" className="text-[10px]">{rel.type.replace('_', ' ')}</Badge>
                                </label>
                            ))}
                        </div>
                    )}
                </div>
            )}

            {/* Sorting & Limits */}
            <div className="grid grid-cols-2 md:grid-cols-3 gap-4">
                <div>
                    <label className="block text-xs font-bold uppercase text-slate-400 mb-1">Sort By</label>
                    <select
                        value={form.orderBy}
                        onChange={(e) => setForm({ ...form, orderBy: e.target.value })}
                        className="w-full px-3 py-2 rounded-lg border border-slate-200 bg-white focus:border-[var(--primary)] focus:ring-2 focus:ring-[var(--primary)]/20 outline-none"
                    >
                        {columns.map(col => (
                            <option key={col.name} value={col.name}>{col.name}</option>
                        ))}
                    </select>
                </div>
                <div>
                    <label className="block text-xs font-bold uppercase text-slate-400 mb-1">Direction</label>
                    <div className="flex bg-slate-100 rounded-lg p-1 border border-slate-200">
                        <button
                            type="button"
                            onClick={() => setForm({ ...form, orderDirection: 'ASC' })}
                            className={`flex-1 py-1 rounded text-xs font-bold transition-all ${form.orderDirection === 'ASC' ? 'bg-white shadow text-slate-800' : 'text-slate-400'}`}
                        >
                            ASC
                        </button>
                        <button
                            type="button"
                            onClick={() => setForm({ ...form, orderDirection: 'DESC' })}
                            className={`flex-1 py-1 rounded text-xs font-bold transition-all ${form.orderDirection === 'DESC' ? 'bg-white shadow text-slate-800' : 'text-slate-400'}`}
                        >
                            DESC
                        </button>
                    </div>
                </div>
                <div>
                    <label className="block text-xs font-bold uppercase text-slate-400 mb-1">Page Size</label>
                    <input
                        type="number"
                        min={1}
                        max={DEFAULTS.resourceForm.maxLimit}
                        value={form.limit}
                        onChange={(e) => setForm({ ...form, limit: parseInt(e.target.value) || DEFAULTS.resourceForm.defaultLimit })}
                        className="w-full px-3 py-2 rounded-lg border border-slate-200 focus:border-[var(--primary)] focus:ring-2 focus:ring-[var(--primary)]/20 outline-none"
                    />
                </div>
            </div>

            {/* Access Control */}
            <div className="bg-slate-50 p-4 rounded-xl border border-slate-100">
                <label className="flex items-start gap-3 cursor-pointer">
                    <input
                        type="checkbox"
                        checked={form.isPublic}
                        onChange={(e) => setForm({ ...form, isPublic: e.target.checked })}
                        className="mt-1 w-5 h-5 rounded border-slate-300 text-[var(--primary)] focus:ring-[var(--primary)]"
                    />
                    <div>
                        <span className="block font-bold text-slate-700">Make Publicly Accessible</span>
                        <p className="text-xs text-slate-500 mt-1">
                            If enabled, this endpoint can be accessed without an API key.
                            <br /><span className="text-amber-600 font-medium">Warning: Use caution for sensitive data.</span>
                        </p>
                    </div>
                </label>
            </div>

            {/* Actions */}
            <div className="flex items-center justify-end gap-3 pt-4 border-t border-slate-100">
                <Button type="button" variant="ghost" onClick={onCancel}>Cancel</Button>
                <Button type="submit" isLoading={submitting} disabled={submitting}>
                    {resource ? 'Update Resource' : 'Create Resource'}
                </Button>
            </div>
        </form>
    );
};

'use client';

// ResourceForm - Premium full-page form for creating/editing resources
// Pure UI component - all data operations via composables

import { useState, useEffect } from 'react';
import { useRouter } from 'next/navigation';
import { Button, Badge } from '@repo/ui';
import { Icons } from '@/modules/_core';
import { useResourceSubmit, type ResourcePayload } from '../composables';
import { DEFAULTS } from '../config';
import type { DataSource, Resource, ColumnDefinition } from '../types';

interface ResourceFormProps {
    dataSource: DataSource;
    resource?: Resource;
}

// Parse JSON safely
const safeParseJSON = <T,>(json: string | undefined | null, fallback: T): T => {
    if (!json) return fallback;
    try {
        return JSON.parse(json);
    } catch {
        return fallback;
    }
};

export const ResourceForm = ({ dataSource, resource }: ResourceFormProps) => {
    const router = useRouter();

    // All data operations from composable
    const {
        submitting,
        create,
        update,
        fetchAvailableSources,
    } = useResourceSubmit(dataSource.id);

    // Available sources for joins (fetched via composable)
    const [availableSources, setAvailableSources] = useState<DataSource[]>([]);

    useEffect(() => {
        fetchAvailableSources(dataSource.id).then(setAvailableSources);
    }, [dataSource.id, fetchAvailableSources]);

    // Form State (UI only)
    const [form, setForm] = useState<{
        name: string;
        slug: string;
        description: string;
        fields: string[];
        orderBy: string;
        orderDirection: 'ASC' | 'DESC';
        limit: number;
        isPublic: boolean;
        aggregates?: { function: 'COUNT' | 'SUM' | 'AVG' | 'MIN' | 'MAX'; column: string; alias?: string }[];
        computed?: { name: string; expression: string }[];
        filters?: { field?: string; operator?: string; value?: any; logic?: 'AND' | 'OR' }[];
        joins?: { table: string; alias: string; type: 'LEFT' | 'INNER'; on: [string, string] }[];
    }>({
        name: resource?.name || '',
        slug: resource?.slug || '',
        description: resource?.description || '',
        fields: safeParseJSON(resource?.fieldsJson, []),
        orderBy: resource?.orderBy || DEFAULTS.resourceForm.orderBy,
        orderDirection: resource?.orderDirection || DEFAULTS.resourceForm.orderDirection,
        limit: resource?.defaultLimit || DEFAULTS.resourceForm.defaultLimit,
        isPublic: resource?.isPublic || DEFAULTS.resourceForm.isPublic,
        aggregates: safeParseJSON(resource?.aggregatesJson, []),
        computed: safeParseJSON(resource?.computedJson, []),
        filters: (() => {
            const f = safeParseJSON(resource?.filtersJson, null);
            if (f && typeof f === 'object' && 'logic' in f && Array.isArray((f as any).filters)) return (f as any).filters;
            return Array.isArray(f) ? f : [];
        })(),
        joins: safeParseJSON(resource?.joinsJson, []),
    });

    const columns = dataSource.schema?.columns || [];

    // Auto-generate slug
    const handleNameChange = (val: string) => {
        const updates: any = { name: val };
        if (!resource && !form.slug && val) {
            updates.slug = val.toLowerCase().replace(/[^a-z0-9]+/g, '-').replace(/^-+|-+$/g, '');
        }
        setForm(prev => ({ ...prev, ...updates }));
    };

    const toggleField = (colName: string) => {
        setForm(prev => {
            const exists = prev.fields.includes(colName);
            if (exists) return { ...prev, fields: prev.fields.filter(f => f !== colName) };
            return { ...prev, fields: [...prev.fields, colName] };
        });
    };

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();

        const payload: ResourcePayload = {
            data_source_id: dataSource.id,
            name: form.name,
            slug: form.slug,
            description: form.description,
            fields_json: JSON.stringify(form.fields),
            order_by: form.orderBy,
            order_direction: form.orderDirection,
            default_limit: form.limit,
            is_public: form.isPublic,
            aggregates_json: JSON.stringify(form.aggregates),
            computed_json: JSON.stringify(form.computed),
            filters_json: JSON.stringify({
                logic: 'AND',
                filters: form.filters
            }),
            joins_json: JSON.stringify(form.joins),
        };

        const result = resource
            ? await update(resource.id, payload)
            : await create(payload);

        if (result) {
            router.push('/data-sources');
            router.refresh();
        }
    };

    return (
        <form onSubmit={handleSubmit} className="space-y-6 animate-in fade-in slide-in-from-bottom-4 duration-500">
            {/* Section: Basic Info */}
            <div className="bg-white rounded-[2rem] border border-slate-100 p-8 shadow-sm">
                <div className="flex items-center gap-3 mb-6">
                    <div className="w-10 h-10 rounded-xl bg-orange-50 flex items-center justify-center text-orange-600 text-xl">≡ƒô¥</div>
                    <h2 className="text-xl font-bold text-slate-800">Endpoint Details</h2>
                </div>

                <div className="grid md:grid-cols-2 gap-8">
                    <div>
                        <label className="block text-sm font-bold text-slate-700 mb-2">Internal Name <span className="text-red-500">*</span></label>
                        <input
                            type="text"
                            value={form.name}
                            onChange={(e) => handleNameChange(e.target.value)}
                            placeholder="e.g. Published Posts"
                            className="w-full px-4 py-3.5 rounded-xl border border-slate-200 focus:ring-4 focus:ring-orange-500/10 focus:border-orange-500 outline-none transition-all font-medium"
                        />
                    </div>
                    <div>
                        <label className="block text-sm font-bold text-slate-700 mb-2">URL Slug <span className="text-red-500">*</span></label>
                        <div className="flex">
                            <span className="bg-slate-50 border border-r-0 border-slate-200 rounded-l-xl px-4 flex items-center text-slate-500 text-sm font-mono">/api/v1/</span>
                            <input
                                type="text"
                                value={form.slug}
                                onChange={(e) => setForm({ ...form, slug: e.target.value.toLowerCase().replace(/[^a-z0-9-]+/g, '') })}
                                placeholder="published-posts"
                                className="w-full px-4 py-3.5 rounded-r-xl border border-slate-200 focus:ring-4 focus:ring-orange-500/10 focus:border-orange-500 outline-none transition-all font-mono text-sm"
                            />
                        </div>
                    </div>
                    <div className="md:col-span-2">
                        <label className="block text-sm font-bold text-slate-700 mb-2">Description</label>
                        <input
                            type="text"
                            value={form.description}
                            onChange={(e) => setForm({ ...form, description: e.target.value })}
                            placeholder="Optional notes for developers"
                            className="w-full px-4 py-3.5 rounded-xl border border-slate-200 focus:ring-4 focus:ring-orange-500/10 focus:border-orange-500 outline-none transition-all"
                        />
                    </div>
                </div>
            </div>

            {/* Section: Fields */}
            <div className="bg-white rounded-[2rem] border border-slate-100 p-8 shadow-sm">
                <div className="flex items-center gap-3 mb-6">
                    <div className="w-10 h-10 rounded-xl bg-blue-50 flex items-center justify-center text-blue-600 text-xl">≡ƒÆá</div>
                    <div>
                        <h2 className="text-xl font-bold text-slate-800">Response Fields</h2>
                        <p className="text-sm text-slate-500">Select which columns to include in the JSON response.</p>
                    </div>
                </div>

                <div className="flex flex-wrap gap-3">
                    {columns.length === 0 && <p className="text-slate-400">No columns defined in schema.</p>}
                    {columns.map(col => {
                        const isSelected = form.fields.length === 0 || form.fields.includes(col.name);
                        return (
                            <button
                                key={col.name}
                                type="button"
                                onClick={() => toggleField(col.name)}
                                className={`
                                    group relative px-4 py-3 rounded-xl border-2 text-sm font-bold transition-all duration-200 flex items-center gap-3
                                    ${isSelected
                                        ? 'bg-blue-50 border-blue-200 text-blue-700 shadow-sm'
                                        : 'bg-white border-slate-100 text-slate-400 hover:border-slate-200'
                                    }
                                `}
                            >
                                <div className={`w-5 h-5 rounded-full flex items-center justify-center border transition-colors ${isSelected ? 'bg-blue-500 border-blue-500 text-white' : 'bg-slate-100 border-slate-200 group-hover:bg-slate-200'}`}>
                                    {isSelected && <span className="text-[10px]">Γ£ô</span>}
                                </div>
                                {col.name}
                            </button>
                        );
                    })}
                </div>
                {form.fields.length === 0 && (
                    <div className="mt-4 p-4 bg-slate-50 rounded-xl border border-slate-100 text-center text-slate-500 text-sm">
                        <span className="font-bold">Γ£¿ All fields selected.</span> Select specific fields to restrict the output.
                    </div>
                )}
            </div>

            {/* Section: Computed Fields */}
            <div className="bg-white rounded-[2rem] border border-slate-100 p-8 shadow-sm">
                <div className="flex items-center gap-3 mb-6">
                    <div className="w-10 h-10 rounded-xl bg-pink-50 flex items-center justify-center text-pink-600 text-xl">ΓÜí</div>
                    <div>
                        <h2 className="text-xl font-bold text-slate-800">Computed Fields</h2>
                        <p className="text-sm text-slate-500">Create new fields using SQL expressions (e.g. `price * 0.2` as `tax`).</p>
                    </div>
                </div>

                {!form.computed || form.computed.length === 0 ? (
                    <div className="text-center p-8 bg-slate-50 rounded-2xl border border-dashed border-slate-300">
                        <p className="text-slate-500 mb-4">No computed fields defined.</p>
                        <Button
                            type="button"
                            variant="ghost"
                            className="text-pink-600 hover:text-pink-700 hover:bg-pink-50"
                            onClick={() => setForm({ ...form, computed: [{ name: '', expression: '' }] })}
                        >
                            + Add Computed Field
                        </Button>
                    </div>
                ) : (
                    <div className="space-y-4">
                        {form.computed.map((comp, idx) => (
                            <div key={idx} className="flex items-center gap-3 bg-slate-50 p-3 rounded-xl border border-slate-200">
                                <span className="text-slate-400 font-mono text-xs">SELECT ... ,</span>
                                <input
                                    type="text"
                                    value={comp.expression}
                                    placeholder="price * quantity"
                                    onChange={(e) => {
                                        const newComp = [...form.computed!];
                                        newComp[idx].expression = e.target.value;
                                        setForm({ ...form, computed: newComp });
                                    }}
                                    className="flex-1 px-3 py-2 rounded-lg border border-slate-200 text-sm font-mono outline-none focus:border-pink-500"
                                />
                                <span className="text-slate-400 text-sm font-bold">AS</span>
                                <input
                                    type="text"
                                    value={comp.name}
                                    placeholder="total_amount"
                                    onChange={(e) => {
                                        const newComp = [...form.computed!];
                                        newComp[idx].name = e.target.value;
                                        setForm({ ...form, computed: newComp });
                                    }}
                                    className="w-48 px-3 py-2 rounded-lg border border-slate-200 text-sm font-bold outline-none focus:border-pink-500"
                                />
                                <button
                                    type="button"
                                    onClick={() => {
                                        const newComp = form.computed!.filter((_, i) => i !== idx);
                                        setForm({ ...form, computed: newComp });
                                    }}
                                    className="w-8 h-8 flex items-center justify-center text-slate-400 hover:text-red-500 hover:bg-red-50 rounded-lg transition-colors"
                                >
                                    ├ù
                                </button>
                            </div>
                        ))}
                        <Button
                            type="button"
                            variant="ghost"
                            size="sm"
                            className="text-pink-600 hover:text-pink-700 hover:bg-pink-50"
                            onClick={() => setForm({ ...form, computed: [...form.computed!, { name: '', expression: '' }] })}
                        >
                            + Add Another Field
                        </Button>
                    </div>
                )}
            </div>

            {/* Section: Aggregates */}
            <div className="bg-white rounded-[2rem] border border-slate-100 p-8 shadow-sm">
                <div className="flex items-center gap-3 mb-6">
                    <div className="w-10 h-10 rounded-xl bg-teal-50 flex items-center justify-center text-teal-600 text-xl">≡ƒôè</div>
                    <div>
                        <h2 className="text-xl font-bold text-slate-800">Aggregates</h2>
                        <p className="text-sm text-slate-500">Calculate totals, averages, and counts instead of listing rows.</p>
                    </div>
                </div>

                {!form.aggregates || form.aggregates.length === 0 ? (
                    <div className="text-center p-8 bg-slate-50 rounded-2xl border border-dashed border-slate-300">
                        <p className="text-slate-500 mb-4">No aggregates defined. Returning standard row data.</p>
                        <Button
                            type="button"
                            variant="primary"
                            onClick={() => setForm({ ...form, aggregates: [{ function: 'COUNT', column: '*' }] })}
                        >
                            + Add Aggregate
                        </Button>
                    </div>
                ) : (
                    <div className="space-y-4">
                        {form.aggregates.map((agg, idx) => (
                            <div key={idx} className="flex items-center gap-3 bg-slate-50 p-3 rounded-xl border border-slate-200">
                                <select
                                    value={agg.function}
                                    onChange={(e) => {
                                        const newAggs = [...form.aggregates!];
                                        newAggs[idx].function = e.target.value as any;
                                        setForm({ ...form, aggregates: newAggs });
                                    }}
                                    className="bg-white border border-slate-200 rounded-lg px-3 py-2 text-sm font-bold outline-none focus:border-teal-500"
                                >
                                    <option value="COUNT">COUNT</option>
                                    <option value="SUM">SUM</option>
                                    <option value="AVG">AVG</option>
                                    <option value="MIN">MIN</option>
                                    <option value="MAX">MAX</option>
                                </select>
                                <span className="text-slate-400">of</span>
                                <select
                                    value={agg.column}
                                    onChange={(e) => {
                                        const newAggs = [...form.aggregates!];
                                        newAggs[idx].column = e.target.value;
                                        setForm({ ...form, aggregates: newAggs });
                                    }}
                                    className="bg-white border border-slate-200 rounded-lg px-3 py-2 text-sm outline-none focus:border-teal-500 flex-1"
                                >
                                    <option value="*">* (All Rows)</option>
                                    {columns.map(c => <option key={c.name} value={c.name}>{c.name}</option>)}
                                </select>
                                <span className="text-slate-400">as</span>
                                <input
                                    type="text"
                                    value={agg.alias || ''}
                                    placeholder={`${agg.column}_${agg.function}`.toLowerCase()}
                                    onChange={(e) => {
                                        const newAggs = [...form.aggregates!];
                                        newAggs[idx].alias = e.target.value;
                                        setForm({ ...form, aggregates: newAggs });
                                    }}
                                    className="bg-white border border-slate-200 rounded-lg px-3 py-2 text-sm outline-none focus:border-teal-500 w-32"
                                />
                                <button
                                    type="button"
                                    onClick={() => {
                                        const newAggs = form.aggregates!.filter((_, i) => i !== idx);
                                        setForm({ ...form, aggregates: newAggs });
                                    }}
                                    className="w-8 h-8 flex items-center justify-center text-slate-400 hover:text-red-500 hover:bg-red-50 rounded-lg transition-colors"
                                >
                                    ├ù
                                </button>
                            </div>
                        ))}
                        <Button
                            type="button"
                            variant="ghost"
                            size="sm"
                            onClick={() => setForm({ ...form, aggregates: [...form.aggregates!, { function: 'COUNT', column: '*' }] })}
                            className="text-teal-600 hover:text-teal-700 hover:bg-teal-50"
                        >
                            + Add Another Aggregate
                        </Button>
                    </div>
                )}
            </div>

            {/* Section: Relations (Joins) */}
            <div className="bg-white rounded-[2rem] border border-slate-100 p-8 shadow-sm">
                <div className="flex items-center gap-3 mb-6">
                    <div className="w-10 h-10 rounded-xl bg-orange-50 flex items-center justify-center text-orange-600 text-xl">≡ƒöù</div>
                    <div>
                        <h2 className="text-xl font-bold text-slate-800">Relations (JOINs)</h2>
                        <p className="text-sm text-slate-500">Connect to other data sources to fetch related data.</p>
                    </div>
                </div>

                {!form.joins || form.joins.length === 0 ? (
                    <div className="text-center p-8 bg-slate-50 rounded-2xl border border-dashed border-slate-300">
                        <p className="text-slate-500 mb-4">No relations defined.</p>
                        <Button
                            type="button"
                            variant="primary"
                            onClick={() => setForm({ ...form, joins: [{ table: availableSources[0]?.tableName || '', alias: '', type: 'LEFT', on: ['', 'id'] }] })}
                            disabled={availableSources.length === 0}
                        >
                            + Add Relation
                        </Button>
                    </div>
                ) : (
                    <div className="space-y-4">
                        {form.joins.map((join, idx) => {
                            const targetSource = availableSources.find(s => s.tableName === join.table);
                            const targetColumns = targetSource?.schema?.columns || [];

                            return (
                                <div key={idx} className="bg-slate-50 p-4 rounded-xl border border-slate-200 space-y-3">
                                    <div className="flex gap-4">
                                        <div className="w-32">
                                            <label className="text-xs font-bold text-slate-500 block mb-1">Type</label>
                                            <select
                                                value={join.type}
                                                onChange={(e) => {
                                                    const newJoins = [...form.joins!];
                                                    newJoins[idx].type = e.target.value as any;
                                                    setForm({ ...form, joins: newJoins });
                                                }}
                                                className="w-full bg-white border border-slate-200 rounded-lg px-3 py-2 text-sm font-bold outline-none focus:border-orange-500"
                                            >
                                                <option value="LEFT">LEFT JOIN</option>
                                                <option value="INNER">INNER JOIN</option>
                                            </select>
                                        </div>
                                        <div className="flex-1">
                                            <label className="text-xs font-bold text-slate-500 block mb-1">Target Table</label>
                                            <select
                                                value={join.table}
                                                onChange={(e) => {
                                                    const newJoins = [...form.joins!];
                                                    newJoins[idx].table = e.target.value;
                                                    const newTargetSource = availableSources.find(s => s.tableName === e.target.value);
                                                    const firstTargetCol = newTargetSource?.schema?.columns[0]?.name || 'id';
                                                    newJoins[idx].on = [newJoins[idx].on[0], firstTargetCol];
                                                    setForm({ ...form, joins: newJoins });
                                                }}
                                                className="w-full bg-white border border-slate-200 rounded-lg px-3 py-2 text-sm outline-none focus:border-orange-500"
                                            >
                                                {availableSources.map(s => <option key={s.id} value={s.tableName}>{s.name} ({s.tableName})</option>)}
                                            </select>
                                        </div>
                                        <div className="w-48">
                                            <label className="text-xs font-bold text-slate-500 block mb-1">Alias (Optional)</label>
                                            <input
                                                type="text"
                                                value={join.alias}
                                                placeholder={join.table}
                                                onChange={(e) => {
                                                    const newJoins = [...form.joins!];
                                                    newJoins[idx].alias = e.target.value;
                                                    setForm({ ...form, joins: newJoins });
                                                }}
                                                className="w-full bg-white border border-slate-200 rounded-lg px-3 py-2 text-sm outline-none focus:border-orange-500 font-mono"
                                            />
                                        </div>
                                        <div>
                                            <label className="block text-xs text-transparent mb-1">Action</label>
                                            <button
                                                type="button"
                                                onClick={() => {
                                                    const newJoins = form.joins!.filter((_, i) => i !== idx);
                                                    setForm({ ...form, joins: newJoins });
                                                }}
                                                className="w-9 h-9 flex items-center justify-center text-slate-400 hover:text-red-500 hover:bg-red-50 rounded-lg transition-colors border border-transparent hover:border-red-200"
                                            >
                                                ≡ƒùæ∩╕Å
                                            </button>
                                        </div>
                                    </div>

                                    <div className="flex items-center gap-3 p-3 bg-white rounded-lg border border-slate-100">
                                        <span className="text-xs font-bold text-slate-400">ON CONDITION</span>
                                        <div className="flex items-center gap-2 flex-1">
                                            <select
                                                value={join.on[0]}
                                                onChange={(e) => {
                                                    const newJoins = [...form.joins!];
                                                    newJoins[idx].on[0] = e.target.value;
                                                    setForm({ ...form, joins: newJoins });
                                                }}
                                                className="flex-1 bg-slate-50 border border-slate-200 rounded px-2 py-1 text-sm outline-none focus:border-orange-500"
                                            >
                                                <option value="" disabled>Select Source Column</option>
                                                {columns.map(c => <option key={c.name} value={c.name}>{dataSource.tableName}.{c.name}</option>)}
                                            </select>
                                            <span className="font-bold text-slate-400">=</span>
                                            <select
                                                value={join.on[1]}
                                                onChange={(e) => {
                                                    const newJoins = [...form.joins!];
                                                    newJoins[idx].on[1] = e.target.value;
                                                    setForm({ ...form, joins: newJoins });
                                                }}
                                                className="flex-1 bg-slate-50 border border-slate-200 rounded px-2 py-1 text-sm outline-none focus:border-orange-500"
                                            >
                                                <option value="" disabled>Select Target Column</option>
                                                {targetColumns.map(c => <option key={c.name} value={c.name}>{join.alias || join.table}.{c.name}</option>)}
                                            </select>
                                        </div>
                                    </div>
                                </div>
                            );
                        })}
                        <Button
                            type="button"
                            variant="ghost"
                            size="sm"
                            onClick={() => setForm({ ...form, joins: [...form.joins!, { table: availableSources[0]?.tableName || '', alias: '', type: 'LEFT', on: ['', 'id'] }] })}
                            className="text-orange-600 hover:text-orange-700 hover:bg-orange-50"
                        >
                            + Add Another Relation
                        </Button>
                    </div>
                )}
            </div>

            {/* Section: Default Filters */}
            <div className="bg-white rounded-[2rem] border border-slate-100 p-8 shadow-sm">
                <div className="flex items-center gap-3 mb-6">
                    <div className="w-10 h-10 rounded-xl bg-indigo-50 flex items-center justify-center text-indigo-600 text-xl">≡ƒöì</div>
                    <div>
                        <h2 className="text-xl font-bold text-slate-800">Default Filters</h2>
                        <p className="text-sm text-slate-500">Apply server-side filters. These will be applied before any client-side query parameters.</p>
                    </div>
                </div>

                {!form.filters || form.filters.length === 0 ? (
                    <div className="text-center p-8 bg-slate-50 rounded-2xl border border-dashed border-slate-300">
                        <p className="text-slate-500 mb-4">No default filters. All data is accessible.</p>
                        <Button
                            type="button"
                            variant="primary"
                            onClick={() => setForm({ ...form, filters: [{ field: columns[0]?.name || '', operator: 'eq', value: '' }] })}
                        >
                            + Add Filter
                        </Button>
                    </div>
                ) : (
                    <div className="space-y-4">
                        {form.filters.map((filter, idx) => (
                            <div key={idx} className="flex items-center gap-2">
                                {idx > 0 && <div className="text-xs font-bold text-slate-400 bg-slate-100 px-2 py-1 rounded">AND</div>}
                                <div className="flex-1 flex items-center gap-3 bg-slate-50 p-3 rounded-xl border border-slate-200">
                                    <select
                                        value={filter.field}
                                        onChange={(e) => {
                                            const newFilters = [...form.filters!];
                                            newFilters[idx].field = e.target.value;
                                            setForm({ ...form, filters: newFilters });
                                        }}
                                        className="bg-white border border-slate-200 rounded-lg px-3 py-2 text-sm font-bold outline-none focus:border-indigo-500"
                                    >
                                        <option value="" disabled>Select Field</option>
                                        {columns.map(c => <option key={c.name} value={c.name}>{c.name}</option>)}
                                    </select>

                                    <select
                                        value={filter.operator}
                                        onChange={(e) => {
                                            const newFilters = [...form.filters!];
                                            newFilters[idx].operator = e.target.value;
                                            setForm({ ...form, filters: newFilters });
                                        }}
                                        className="bg-white border border-slate-200 rounded-lg px-3 py-2 text-sm outline-none focus:border-indigo-500 w-32"
                                    >
                                        <option value="eq">Equals (=)</option>
                                        <option value="neq">Not Equal (!=)</option>
                                        <option value="gt">Greater (&gt;)</option>
                                        <option value="gte">Greater/Eq (&gt;=)</option>
                                        <option value="lt">Less (&lt;)</option>
                                        <option value="lte">Less/Eq (&lt;=)</option>
                                        <option value="like">Contains (LIKE)</option>
                                        <option value="in">In List (IN)</option>
                                        <option value="null">Is Null</option>
                                        <option value="notNull">Is Not Null</option>
                                    </select>

                                    {!['null', 'notNull'].includes(filter.operator!) && (
                                        <input
                                            type="text"
                                            value={filter.value || ''}
                                            placeholder={filter.operator === 'in' ? 'val1,val2,val3' : 'Value'}
                                            onChange={(e) => {
                                                const newFilters = [...form.filters!];
                                                newFilters[idx].value = filter.operator === 'in' ? e.target.value.split(',') : e.target.value;
                                                setForm({ ...form, filters: newFilters });
                                            }}
                                            className="flex-1 bg-white border border-slate-200 rounded-lg px-3 py-2 text-sm outline-none focus:border-indigo-500"
                                        />
                                    )}

                                    <button
                                        type="button"
                                        onClick={() => {
                                            const newFilters = form.filters!.filter((_, i) => i !== idx);
                                            setForm({ ...form, filters: newFilters });
                                        }}
                                        className="w-8 h-8 flex items-center justify-center text-slate-400 hover:text-red-500 hover:bg-red-50 rounded-lg transition-colors"
                                    >
                                        ├ù
                                    </button>
                                </div>
                            </div>
                        ))}
                        <Button
                            type="button"
                            variant="ghost"
                            size="sm"
                            onClick={() => setForm({ ...form, filters: [...form.filters!, { field: columns[0]?.name || '', operator: 'eq', value: '' }] })}
                            className="text-indigo-600 hover:text-indigo-700 hover:bg-indigo-50"
                        >
                            + Add Filter
                        </Button>
                    </div>
                )}
            </div>

            {/* Section: Config */}
            <div className="bg-white rounded-[2rem] border border-slate-100 p-8 shadow-sm">
                <div className="flex items-center gap-3 mb-6">
                    <div className="w-10 h-10 rounded-xl bg-purple-50 flex items-center justify-center text-purple-600 text-xl">ΓÜÖ∩╕Å</div>
                    <h2 className="text-xl font-bold text-slate-800">Configuration</h2>
                </div>

                <div className="grid md:grid-cols-3 gap-6">
                    <div>
                        <label className="block text-sm font-bold text-slate-700 mb-2">Default Sort Config</label>
                        <div className="flex gap-2">
                            <select
                                value={form.orderBy}
                                onChange={(e) => setForm({ ...form, orderBy: e.target.value })}
                                className="flex-1 px-4 py-3 rounded-xl border border-slate-200 bg-white outline-none focus:border-purple-500 focus:ring-4 focus:ring-purple-500/10"
                            >
                                {columns.map(col => (
                                    <option key={col.name} value={col.name}>{col.name}</option>
                                ))}
                            </select>
                            <div className="flex bg-slate-100 p-1 rounded-xl">
                                <button
                                    type="button"
                                    onClick={() => setForm({ ...form, orderDirection: 'ASC' })}
                                    className={`px-3 rounded-lg text-xs font-bold transition-all ${form.orderDirection === 'ASC' ? 'bg-white shadow text-slate-800' : 'text-slate-400'}`}
                                >
                                    ASC
                                </button>
                                <button
                                    type="button"
                                    onClick={() => setForm({ ...form, orderDirection: 'DESC' })}
                                    className={`px-3 rounded-lg text-xs font-bold transition-all ${form.orderDirection === 'DESC' ? 'bg-white shadow text-slate-800' : 'text-slate-400'}`}
                                >
                                    DESC
                                </button>
                            </div>
                        </div>
                    </div>

                    <div>
                        <label className="block text-sm font-bold text-slate-700 mb-2">Limit Per Page</label>
                        <input
                            type="number"
                            min={1}
                            max={DEFAULTS.resourceForm.maxLimit}
                            value={form.limit}
                            onChange={(e) => setForm({ ...form, limit: parseInt(e.target.value) || DEFAULTS.resourceForm.defaultLimit })}
                            className="w-full px-4 py-3 rounded-xl border border-slate-200 outline-none focus:border-purple-500 focus:ring-4 focus:ring-purple-500/10"
                        />
                    </div>
                </div>

                <div className="mt-8 pt-8 border-t border-slate-100">
                    <label className={`
                        flex items-start gap-4 p-4 rounded-xl border transition-all cursor-pointer
                        ${form.isPublic
                            ? 'bg-amber-50 border-amber-200'
                            : 'bg-white border-slate-200 hover:border-slate-300'
                        }
                    `}>
                        <div className={`mt-1 w-6 h-6 rounded-lg border-2 flex items-center justify-center transition-colors ${form.isPublic ? 'bg-amber-500 border-amber-500 text-white' : 'bg-white border-slate-300'}`}>
                            {form.isPublic && <span>Γ£ô</span>}
                        </div>
                        <input
                            type="checkbox"
                            checked={form.isPublic}
                            onChange={(e) => setForm({ ...form, isPublic: e.target.checked })}
                            className="hidden"
                        />
                        <div>
                            <span className={`block font-bold text-lg ${form.isPublic ? 'text-amber-800' : 'text-slate-800'}`}>
                                Public Access
                            </span>
                            <p className="text-sm text-slate-500 mt-1">
                                {form.isPublic
                                    ? "ΓÜá∩╕Å This endpoint will be accessible by anyone without an API key."
                                    : "≡ƒöÆ Access requires a valid API Key (Recommended)."
                                }
                            </p>
                        </div>
                    </label>
                </div>
            </div>

            {/* Sticky Actions Footer */}
            <div className="sticky bottom-4 z-10">
                <div className="bg-white/80 backdrop-blur-xl p-4 rounded-2xl border border-slate-200 shadow-2xl flex items-center justify-between">
                    <Button type="button" variant="ghost" onClick={() => router.back()} className="text-slate-500 hover:text-slate-800">
                        Cancel
                    </Button>
                    <Button type="submit" size="lg" isLoading={submitting} className="px-8 shadow-lg shadow-primary/20">
                        {resource ? 'Save Changes' : 'Create Resource'}
                    </Button>
                </div>
            </div>
            <div className="h-4"></div>
        </form>
    );
};

'use client';

// ResourceModal - Wrapper modal for ResourceEditor
// Provides context (fixed overlay, animation)

import { useState, useEffect } from 'react';
import { ResourceEditor } from './ResourceEditor';
import { DataSource, Resource } from '../types';

interface ResourceModalProps {
    isOpen: boolean;
    onClose: () => void;
    dataSource: DataSource | null;
    resource?: Resource; // If editing
    onSaved: () => void;
}

export const ResourceModal = ({ isOpen, onClose, dataSource, resource, onSaved }: ResourceModalProps) => {
    const [isVisible, setIsVisible] = useState(false);

    useEffect(() => {
        if (isOpen) {
            setIsVisible(true);
            // Prevent body scroll
            document.body.style.overflow = 'hidden';
        } else {
            const timer = setTimeout(() => setIsVisible(false), 300);
            document.body.style.overflow = 'unset';
            return () => clearTimeout(timer);
        }
    }, [isOpen]);

    if (!isVisible) return null;

    return (
        <div className={`fixed inset-0 z-50 flex items-center justify-center p-4 transition-all duration-300 ${isOpen ? 'opacity-100' : 'opacity-0'}`}>
            {/* Backdrop */}
            <div
                className="absolute inset-0 bg-slate-900/40 backdrop-blur-sm transition-opacity"
                onClick={onClose}
            />

            {/* Modal Content */}
            <div className={`
                relative w-full max-w-2xl bg-white rounded-2xl shadow-2xl overflow-hidden
                transform transition-all duration-300
                ${isOpen ? 'scale-100 translate-y-0' : 'scale-95 translate-y-8'}
            `}>
                <div className="absolute top-4 right-4 z-10">
                    <button
                        onClick={onClose}
                        className="w-8 h-8 rounded-full bg-slate-100 text-slate-400 hover:bg-slate-200 hover:text-slate-600 flex items-center justify-center transition-colors"
                    >
                        Γ£ò
                    </button>
                </div>

                <div className="p-8 max-h-[90vh] overflow-y-auto">
                    {dataSource && (
                        <ResourceEditor
                            dataSource={dataSource}
                            resource={resource}
                            onSave={() => {
                                onSaved();
                                onClose();
                            }}
                            onCancel={onClose}
                        />
                    )}
                </div>
            </div>
        </div>
    );
};

'use client';

// SchemaEditor - Pure UI component for editing data source schema
// Uses useSchemaEditor and useDataSources composables

import { useState, useEffect, useMemo } from 'react';
import { useRouter } from 'next/navigation';
import { Button } from '@repo/ui';
import { useToast, Icons } from '@/modules/_core';
import { ColumnBuilder } from './ColumnBuilder';
import { RelationBuilder } from './RelationBuilder';
import { useDataSources, useSchemaEditor } from '../composables';
import type { ColumnDefinition, DataSource } from '../types';

interface SchemaEditorProps {
    dataSourceId: number;
}

export const SchemaEditor = ({ dataSourceId }: SchemaEditorProps) => {
    const router = useRouter();
    const { addToast } = useToast();

    // Data from composables
    const { items: allSources, fetchOne, loading: sourcesLoading } = useDataSources();
    const { addColumn, dropColumn, loading: schemaLoading } = useSchemaEditor(dataSourceId);

    // Local state for UI
    const [source, setSource] = useState<DataSource | null>(null);
    const [columns, setColumns] = useState<ColumnDefinition[]>([]);
    const [originalColumns, setOriginalColumns] = useState<ColumnDefinition[]>([]);
    const [loading, setLoading] = useState(true);
    const [saving, setSaving] = useState(false);

    // Compute available sources for relation picker
    const availableSources = useMemo(() => {
        return allSources.map((s) => ({
            label: s.name,
            value: s.tableName,
        }));
    }, [allSources]);

    // Fetch source details
    useEffect(() => {
        const loadSource = async () => {
            setLoading(true);
            const data = await fetchOne(dataSourceId);
            if (data) {
                setSource(data);
                const schema = data.schemaJson ? JSON.parse(data.schemaJson) : { columns: [] };
                setColumns(schema.columns);
                setOriginalColumns(JSON.parse(JSON.stringify(schema.columns)));
            }
            setLoading(false);
        };

        if (dataSourceId) {
            loadSource();
        }
    }, [dataSourceId, fetchOne]);

    // Handle save - detect changes and apply them
    const handleSave = async () => {
        setSaving(true);

        const originalMap = new Map(originalColumns.map(c => [c.name, c]));
        const newMap = new Map(columns.map(c => [c.name, c]));

        const toAdd: ColumnDefinition[] = [];
        const toDrop: string[] = [];

        // Identify Added
        for (const col of columns) {
            if (!originalMap.has(col.name)) {
                toAdd.push(col);
            }
        }

        // Identify Dropped
        for (const orgCol of originalColumns) {
            if (!newMap.has(orgCol.name)) {
                toDrop.push(orgCol.name);
            }
        }

        if (toAdd.length === 0 && toDrop.length === 0) {
            addToast('No changes detected', 'info');
            setSaving(false);
            return;
        }

        let hasError = false;

        // Execute changes using composable
        for (const colName of toDrop) {
            const success = await dropColumn(colName);
            if (!success) hasError = true;
        }

        for (const col of toAdd) {
            const success = await addColumn(col);
            if (!success) hasError = true;
        }

        if (!hasError) {
            // Update original columns to reflect current state
            setOriginalColumns(JSON.parse(JSON.stringify(columns)));
        }

        setSaving(false);
    };

    // Handle refresh after relation changes
    const handleRefresh = async () => {
        const data = await fetchOne(dataSourceId);
        if (data) {
            setSource(data);
            const schema = data.schemaJson ? JSON.parse(data.schemaJson) : { columns: [] };
            setColumns(schema.columns);
            setOriginalColumns(JSON.parse(JSON.stringify(schema.columns)));
        }
    };

    // Loading state
    if (loading) {
        return (
            <div className="p-8 text-center text-slate-400">
                Loading schema...
            </div>
        );
    }

    return (
        <div className="space-y-6 animate-page-enter">
            {/* Header */}
            <div className="flex items-center justify-between">
                <div>
                    <h2 className="text-2xl font-bold text-slate-800">Edit Schema</h2>
                    <p className="text-slate-500">Modify structure for {source?.name}</p>
                </div>
                <div className="flex gap-2">
                    <Button variant="ghost" onClick={() => router.back()}>Cancel</Button>
                    <Button
                        onClick={handleSave}
                        isLoading={saving || schemaLoading}
                        disabled={saving || schemaLoading}
                    >
                        Save Changes
                    </Button>
                </div>
            </div>

            {/* Columns Section */}
            <div className="bg-white rounded-[2rem] border border-slate-100 p-8 shadow-sm">
                <ColumnBuilder
                    columns={columns}
                    onChange={setColumns}
                    availableSources={availableSources}
                />
            </div>

            {/* Relations Section */}
            <div className="bg-white rounded-[2rem] border border-slate-100 p-8 shadow-sm">
                <RelationBuilder
                    dataSourceId={dataSourceId}
                    dataSourceName={source?.name || 'Unknown'}
                    onRelationsChange={handleRefresh}
                />
            </div>

            {/* Warning Banner */}
            <div className="bg-amber-50 rounded-xl p-4 border border-amber-200 flex gap-3 text-amber-800 text-sm">
                <span className="text-xl">ΓÜá∩╕Å</span>
                <div>
                    <p className="font-bold">Warning: Schema Changes</p>
                    <p className="opacity-90 mt-1">
                        Dropping columns will permanently delete associated data.
                        Modifying data types may truncate content.
                        Renaming columns is currently treated as Drop + Add (Data Loss).
                    </p>
                </div>
            </div>
        </div>
    );
};
